{
  "name": "Luggage Deposit Rome Admin Dashboard",
  "description": "A secure admin panel to manage luggage storage bookings, track status, and handle customer communication."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type BookingStatus = 'paid' | 'checked_in' | 'picked_up' | 'cancelled';

export interface Customer {
  name: string;
  email: string;
  phone: string;
}

export interface BagCount {
  small: number;
  medium: number;
  large: number;
}

export interface BookingDateTime {
  date: string;
  time: string;
  datetime: any; // Firestore Timestamp
}

export interface Booking {
  id: string; // Document ID
  bookingRef: string;
  stripeSessionId: string;
  createdAt: any; // Firestore Timestamp
  bookedOnRome: string;
  customer: Customer;
  dropOff: BookingDateTime;
  pickUp: BookingDateTime;
  billableDays: number;
  bags: BagCount;
  totalPaid: number;
  currency: string;
  status: BookingStatus;
  notes: string;
  walletIssued: boolean;
}

export interface AdminUser {
  email: string;
  role: 'admin';
}

import { initializeApp } from 'firebase/app';
import { getAuth } from 'firebase/auth';
import { getFirestore } from 'firebase/firestore';

// Note: In a real environment, these are injected by Vercel from Environment Variables
const firebaseConfig = {
  apiKey: (window as any).FIREBASE_API_KEY || "YOUR_API_KEY",
  authDomain: "luggage-deposit-rome.firebaseapp.com",
  projectId: "luggage-deposit-rome",
  storageBucket: "luggage-deposit-rome.appspot.com",
  messagingSenderId: "YOUR_SENDER_ID",
  appId: "YOUR_APP_ID"
};

const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);
export const db = getFirestore(app);

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { onAuthStateChanged, User } from 'firebase/auth';
import { doc, getDoc } from 'firebase/firestore';
import { auth, db } from './firebase';
import LoginPage from './pages/LoginPage';
import DashboardPage from './pages/DashboardPage';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [isAdmin, setIsAdmin] = useState<boolean | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      if (currentUser) {
        // Check if user is in the admins collection
        const adminDoc = await getDoc(doc(db, 'admins', currentUser.email || ''));
        if (adminDoc.exists()) {
          setUser(currentUser);
          setIsAdmin(true);
        } else {
          // Logged in but not an admin
          setUser(null);
          setIsAdmin(false);
          await auth.signOut();
        }
      } else {
        setUser(null);
        setIsAdmin(null);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  if (loading) {
    return (
      <div className="flex h-screen items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center space-y-4">
          <div className="h-12 w-12 animate-spin rounded-full border-4 border-blue-600 border-t-transparent"></div>
          <p className="text-slate-500 font-medium">Verifying access...</p>
        </div>
      </div>
    );
  }

  return (
    <HashRouter>
      <Routes>
        <Route 
          path="/login" 
          element={user && isAdmin ? <Navigate to="/" /> : <LoginPage />} 
        />
        <Route 
          path="/" 
          element={user && isAdmin ? <DashboardPage /> : <Navigate to="/login" />} 
        />
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </HashRouter>
  );
};

export default App;

import React from 'react';
import { BookingStatus } from '../types';

interface StatusBadgeProps {
  status: BookingStatus;
}

const StatusBadge: React.FC<StatusBadgeProps> = ({ status }) => {
  const styles: Record<BookingStatus, string> = {
    paid: 'bg-emerald-100 text-emerald-700 border-emerald-200',
    checked_in: 'bg-blue-100 text-blue-700 border-blue-200',
    picked_up: 'bg-slate-100 text-slate-700 border-slate-200',
    cancelled: 'bg-red-100 text-red-700 border-red-200',
  };

  const labels: Record<BookingStatus, string> = {
    paid: 'Paid',
    checked_in: 'Checked In',
    picked_up: 'Picked Up',
    cancelled: 'Cancelled',
  };

  return (
    <span className={`px-2.5 py-0.5 rounded-full text-xs font-semibold border ${styles[status]}`}>
      {labels[status]}
    </span>
  );
};

export default StatusBadge;

import React, { useState } from 'react';
import { Booking, BookingStatus } from '../types';
import { doc, updateDoc } from 'firebase/firestore';
import { db } from '../firebase';
import StatusBadge from './StatusBadge';

interface BookingDetailModalProps {
  booking: Booking;
  onClose: () => void;
  onUpdate: () => void;
}

const BookingDetailModal: React.FC<BookingDetailModalProps> = ({ booking, onClose, onUpdate }) => {
  const [notes, setNotes] = useState(booking.notes || '');
  const [updating, setUpdating] = useState(false);

  const updateStatus = async (newStatus: BookingStatus) => {
    setUpdating(true);
    try {
      const bookingRef = doc(db, 'bookings', booking.id);
      await updateDoc(bookingRef, { status: newStatus });
      onUpdate();
    } catch (err) {
      alert('Failed to update status');
    } finally {
      setUpdating(false);
    }
  };

  const saveNotes = async () => {
    setUpdating(true);
    try {
      const bookingRef = doc(db, 'bookings', booking.id);
      await updateDoc(bookingRef, { notes });
      onUpdate();
    } catch (err) {
      alert('Failed to save notes');
    } finally {
      setUpdating(false);
    }
  };

  const resendEmail = async () => {
    setUpdating(true);
    try {
      const response = await fetch('/api/admin/resend-email', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ bookingRef: booking.bookingRef }),
      });
      if (response.ok) alert('Confirmation email resent!');
      else alert('Failed to resend email');
    } catch (err) {
      alert('Network error resending email');
    } finally {
      setUpdating(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto">
        <div className="sticky top-0 bg-white border-b px-6 py-4 flex items-center justify-between">
          <h2 className="text-xl font-bold">Booking #{booking.bookingRef}</h2>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="p-6 space-y-8">
          {/* Quick Stats */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <div className="p-3 bg-slate-50 rounded-lg">
              <p className="text-xs text-slate-500 mb-1">Status</p>
              <StatusBadge status={booking.status} />
            </div>
            <div className="p-3 bg-slate-50 rounded-lg">
              <p className="text-xs text-slate-500 mb-1">Paid</p>
              <p className="font-bold">{booking.totalPaid} {booking.currency.toUpperCase()}</p>
            </div>
            <div className="p-3 bg-slate-50 rounded-lg">
              <p className="text-xs text-slate-500 mb-1">Duration</p>
              <p className="font-bold">{booking.billableDays} Days</p>
            </div>
            <div className="p-3 bg-slate-50 rounded-lg">
              <p className="text-xs text-slate-500 mb-1">Bags</p>
              <p className="font-bold">{booking.bags.small + booking.bags.medium + booking.bags.large}</p>
            </div>
          </div>

          <div className="grid md:grid-cols-2 gap-8">
            {/* Customer */}
            <section>
              <h3 className="text-sm font-semibold uppercase tracking-wider text-slate-500 mb-3">Customer Info</h3>
              <div className="space-y-2">
                <p className="font-medium text-lg">{booking.customer.name}</p>
                <p className="text-slate-600">{booking.customer.email}</p>
                <p className="text-slate-600">{booking.customer.phone}</p>
              </div>
            </section>

            {/* Schedule */}
            <section>
              <h3 className="text-sm font-semibold uppercase tracking-wider text-slate-500 mb-3">Schedule</h3>
              <div className="space-y-4">
                <div>
                  <p className="text-xs text-slate-500">Drop-off</p>
                  <p className="font-medium">{booking.dropOff.date} @ {booking.dropOff.time}</p>
                </div>
                <div>
                  <p className="text-xs text-slate-500">Pick-up</p>
                  <p className="font-medium">{booking.pickUp.date} @ {booking.pickUp.time}</p>
                </div>
              </div>
            </section>
          </div>

          {/* Internal Notes */}
          <section>
            <h3 className="text-sm font-semibold uppercase tracking-wider text-slate-500 mb-3">Internal Notes</h3>
            <textarea
              className="w-full p-3 border rounded-lg h-24 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
              placeholder="Private admin notes..."
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
            />
            <button
              onClick={saveNotes}
              disabled={updating}
              className="mt-2 text-sm text-blue-600 font-semibold hover:text-blue-700 disabled:opacity-50"
            >
              Save Notes
            </button>
          </section>

          {/* Actions */}
          <section className="bg-slate-50 p-4 rounded-xl space-y-4">
            <h3 className="text-sm font-semibold text-slate-600">Administrative Actions</h3>
            <div className="flex flex-wrap gap-2">
              <button 
                onClick={() => updateStatus('checked_in')}
                disabled={updating || booking.status === 'checked_in'}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700 disabled:opacity-50"
              >
                Check In
              </button>
              <button 
                onClick={() => updateStatus('picked_up')}
                disabled={updating || booking.status === 'picked_up'}
                className="px-4 py-2 bg-emerald-600 text-white rounded-lg text-sm font-medium hover:bg-emerald-700 disabled:opacity-50"
              >
                Mark Picked Up
              </button>
              <button 
                onClick={() => updateStatus('cancelled')}
                disabled={updating || booking.status === 'cancelled'}
                className="px-4 py-2 bg-slate-200 text-slate-700 rounded-lg text-sm font-medium hover:bg-slate-300 disabled:opacity-50"
              >
                Cancel
              </button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 pt-4 border-t border-slate-200">
              <a 
                href={`https://booking.luggagedepositrome.com/api/r?session_id=${booking.stripeSessionId}`} 
                target="_blank" 
                rel="noreferrer"
                className="text-center px-4 py-2 border rounded-lg text-sm font-medium text-slate-600 hover:bg-white"
              >
                View Success Page
              </a>
              <a 
                href={`https://booking.luggagedepositrome.com/api/google-wallet?session_id=${booking.stripeSessionId}`} 
                target="_blank" 
                rel="noreferrer"
                className="text-center px-4 py-2 border rounded-lg text-sm font-medium text-slate-600 hover:bg-white"
              >
                Re-issue Wallet Pass
              </a>
              <button 
                onClick={resendEmail}
                disabled={updating}
                className="col-span-full px-4 py-2 bg-slate-800 text-white rounded-lg text-sm font-medium hover:bg-slate-900"
              >
                Resend Confirmation Email
              </button>
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default BookingDetailModal;

import React, { useState } from 'react';
import { signInWithEmailAndPassword } from 'firebase/auth';
import { auth } from '../firebase';

const LoginPage: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (err: any) {
      setError('Access denied. Please check your credentials.');
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4">
      <div className="max-w-md w-full">
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center w-20 h-20 bg-blue-600 rounded-2xl mb-4 shadow-xl shadow-blue-200">
            <svg className="w-10 h-10 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
            </svg>
          </div>
          <h1 className="text-3xl font-bold text-slate-900">Admin Portal</h1>
          <p className="text-slate-500 mt-2">Luggage Deposit Rome Management</p>
        </div>

        <form onSubmit={handleLogin} className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 space-y-6">
          {error && (
            <div className="p-3 bg-red-50 text-red-600 text-sm rounded-xl border border-red-100 font-medium">
              {error}
            </div>
          )}

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Email Address</label>
            <input
              type="email"
              required
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
              placeholder="admin@luggagedepositrome.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Password</label>
            <input
              type="password"
              required
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-blue-600 text-white py-3 rounded-xl font-bold text-lg hover:bg-blue-700 shadow-lg shadow-blue-200 transition-all disabled:opacity-50"
          >
            {loading ? 'Signing in...' : 'Sign In'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default LoginPage;

import React, { useState, useEffect } from 'react';
import { collection, query, orderBy, onSnapshot, Timestamp } from 'firebase/firestore';
import { signOut } from 'firebase/auth';
import { auth, db } from '../firebase';
import { Booking, BookingStatus } from '../types';
import StatusBadge from '../components/StatusBadge';
import BookingDetailModal from '../components/BookingDetailModal';

type DateFilter = 'all' | 'today' | 'upcoming' | 'past';

const DashboardPage: React.FC = () => {
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [filteredBookings, setFilteredBookings] = useState<Booking[]>([]);
  const [search, setSearch] = useState('');
  const [dateFilter, setDateFilter] = useState<DateFilter>('all');
  const [statusFilter, setStatusFilter] = useState<BookingStatus | 'all'>('all');
  const [selectedBooking, setSelectedBooking] = useState<Booking | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const q = query(collection(db, 'bookings'), orderBy('dropOff.datetime', 'asc'));

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const docs = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as Booking[];
      setBookings(docs);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const now = new Date();
    const todayStr = now.toISOString().split('T')[0];

    let result = bookings.filter(b => {
      // Search logic
      const s = search.toLowerCase();
      const matchesSearch = !search || 
        b.bookingRef.toLowerCase().includes(s) || 
        b.customer.email.toLowerCase().includes(s) || 
        b.customer.phone.toLowerCase().includes(s) ||
        b.customer.name.toLowerCase().includes(s);

      // Status logic
      const matchesStatus = statusFilter === 'all' || b.status === statusFilter;

      // Date logic
      const bookingDate = b.dropOff.date;
      let matchesDate = true;
      if (dateFilter === 'today') matchesDate = bookingDate === todayStr;
      else if (dateFilter === 'upcoming') matchesDate = bookingDate > todayStr;
      else if (dateFilter === 'past') matchesDate = bookingDate < todayStr;

      return matchesSearch && matchesStatus && matchesDate;
    });

    setFilteredBookings(result);
  }, [bookings, search, dateFilter, statusFilter]);

  const handleLogout = () => signOut(auth);

  return (
    <div className="min-h-screen bg-slate-50 pb-12">
      {/* Header */}
      <header className="bg-white border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold">R</div>
            <h1 className="font-bold text-xl text-slate-900 hidden sm:block">Admin Console</h1>
          </div>
          <div className="flex items-center gap-4">
            <span className="text-sm text-slate-500 font-medium hidden md:block">{auth.currentUser?.email}</span>
            <button 
              onClick={handleLogout}
              className="text-sm font-semibold text-slate-600 hover:text-red-600 transition-colors"
            >
              Sign Out
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 mt-8">
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6 mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">Manage Bookings</h2>
            <p className="text-slate-500">Track and update luggage storage requests</p>
          </div>

          <div className="flex flex-col sm:flex-row gap-4">
            {/* Search */}
            <div className="relative">
              <input
                type="text"
                placeholder="Ref, Email, Phone..."
                className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 w-full sm:w-64 transition-all"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
              <svg className="w-5 h-5 absolute left-3 top-2.5 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </div>
          </div>
        </div>

        {/* Filters */}
        <div className="flex flex-wrap gap-2 mb-6">
          <div className="flex bg-white p-1 rounded-xl border border-slate-200">
            {(['all', 'today', 'upcoming', 'past'] as const).map((f) => (
              <button
                key={f}
                onClick={() => setDateFilter(f)}
                className={`px-4 py-1.5 text-sm font-semibold rounded-lg transition-all capitalize ${dateFilter === f ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'}`}
              >
                {f}
              </button>
            ))}
          </div>

          <div className="flex bg-white p-1 rounded-xl border border-slate-200">
            {(['all', 'paid', 'checked_in', 'picked_up', 'cancelled'] as const).map((s) => (
              <button
                key={s}
                onClick={() => setStatusFilter(s)}
                className={`px-4 py-1.5 text-sm font-semibold rounded-lg transition-all capitalize ${statusFilter === s ? 'bg-slate-800 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'}`}
              >
                {s.replace('_', ' ')}
              </button>
            ))}
          </div>
        </div>

        {/* Table/List */}
        <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
          {loading ? (
            <div className="p-20 text-center text-slate-400">Loading bookings...</div>
          ) : filteredBookings.length === 0 ? (
            <div className="p-20 text-center">
              <p className="text-slate-500 mb-2">No bookings found matching your criteria</p>
              <button onClick={() => { setSearch(''); setDateFilter('all'); setStatusFilter('all'); }} className="text-blue-600 font-semibold text-sm underline">Clear all filters</button>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                    <th className="px-6 py-4">Ref</th>
                    <th className="px-6 py-4">Customer</th>
                    <th className="px-6 py-4">Drop-off</th>
                    <th className="px-6 py-4">Bags</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4">Total</th>
                    <th className="px-6 py-4"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filteredBookings.map((booking) => (
                    <tr 
                      key={booking.id} 
                      className="hover:bg-slate-50/80 transition-colors cursor-pointer group"
                      onClick={() => setSelectedBooking(booking)}
                    >
                      <td className="px-6 py-4">
                        <span className="font-mono font-bold text-slate-900">#{booking.bookingRef}</span>
                        <div className="text-[10px] text-slate-400">{booking.bookedOnRome}</div>
                      </td>
                      <td className="px-6 py-4">
                        <p className="font-semibold text-slate-900">{booking.customer.name}</p>
                        <p className="text-xs text-slate-500">{booking.customer.email}</p>
                      </td>
                      <td className="px-6 py-4">
                        <p className="text-sm font-medium">{booking.dropOff.date}</p>
                        <p className="text-xs text-slate-400">{booking.dropOff.time}</p>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-sm px-2 py-1 bg-slate-100 rounded-md font-medium text-slate-700">
                          {booking.bags.small + booking.bags.medium + booking.bags.large}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <StatusBadge status={booking.status} />
                      </td>
                      <td className="px-6 py-4">
                        <p className="text-sm font-bold text-slate-900">{booking.totalPaid} {booking.currency.toUpperCase()}</p>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button className="p-2 hover:bg-white border border-transparent hover:border-slate-200 rounded-lg transition-all opacity-0 group-hover:opacity-100">
