service cloud.firestore {
  match /databases/{database}/documents {
    // Only authenticated users who exist in the 'admins' collection can read/write
    match /bookings/{bookingId} {
      allow read, write: if request.auth != null && exists(/databases/$(database)/documents/admins/$(request.auth.token.email));
    }

    // Admin list itself is only readable/writable by other admins (or manually via console)
    match /admins/{adminEmail} {
