service cloud.firestore {
  match /databases/{database}/documents {
    // Helper function to check if the user is in the admins allow-list
    function isAdmin() {
      return request.auth != null && 
             exists(/databases/$(database)/documents/admins/$(request.auth.token.email)) &&
             get(/databases/$(database)/documents/admins/$(request.auth.token.email)).data.active == true;
    }

    // Bookings: Only allowed if the user is a verified admin
    match /bookings/{bookingId} {
      allow read, write: if isAdmin();
    }

    // Admins Collection: 
    // - Users can read their own admin entry to verify status
    // - Only existing admins can read the list of other admins
    // - Write access is restricted to manual console or Admin SDK
    match /admins/{adminEmail} {
      allow read: if request.auth != null && (request.auth.token.email == adminEmail || isAdmin());
      allow write: if false; 
    }
  }
}

