type DateFilter = 'all' | 'today' | 'upcoming' | 'past';

const DashboardPage: React.FC = () => {
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [filteredBookings, setFilteredBookings] = useState<Booking[]>([]);
  const [search, setSearch] = useState('');
  const [dateFilter, setDateFilter] = useState<DateFilter>('all');
  const [statusFilter, setStatusFilter] = useState<BookingStatus | 'all'>('all');
  const [selectedBooking, setSelectedBooking] = useState<Booking | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const logoUrl = "https://cdn.shopify.com/s/files/1/0753/8144/0861/files/cropped-Untitled-design-2025-09-11T094640.576_1.png?v=1765462614&width=160&format=webp";

  useEffect(() => {
    console.log("Initializing Firestore listener for 'bookings' collection...");
    setLoading(true);
    setError(null);

    // TASK 2: Simplified query to guarantee results regardless of indexes or field existence
    const bookingsCol = collection(db, 'bookings');

    const unsubscribe = onSnapshot(
      bookingsCol, 
      (snapshot) => {
        const docs = snapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        })) as Booking[];

        // TASK 2: Log doc count and sample data
        console.log(`Successfully fetched ${docs.length} bookings.`);
        if (docs.length > 0) {
          console.log("Sample Booking ID:", docs[0].id);
          console.table(docs.slice(0, 3).map(d => ({ ref: d.bookingRef, status: d.status, customer: d.customer?.name })));
        }

        // TASK 5: Safely sort client-side (Newest first)
        const sortedDocs = [...docs].sort((a, b) => {
          const timeA = a.createdAt?.seconds || 0;
          const timeB = b.createdAt?.seconds || 0;
          return timeB - timeA;
        });

        setBookings(sortedDocs);
        setLoading(false);
      },
      (err) => {
        // TASK 4: Error Handling
        console.error("Firestore Subscription Error:", err);
        setError(`Failed to load data: ${err.message}`);
        setLoading(false);
      }
    );

    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const now = new Date();
    const todayStr = now.toISOString().split('T')[0];

    let result = bookings.filter(b => {
      // Search logic
      const s = search.toLowerCase();
      const matchesSearch = !search || 
        (b.bookingRef || '').toLowerCase().includes(s) || 
        (b.customer?.email || '').toLowerCase().includes(s) || 
        (b.customer?.phone || '').toLowerCase().includes(s) ||
        (b.customer?.name || '').toLowerCase().includes(s);

      // Status logic
      const matchesStatus = statusFilter === 'all' || b.status === statusFilter;

      // Date logic
      const bookingDate = b.dropOff?.date;
      let matchesDate = true;
      if (dateFilter === 'today') matchesDate = bookingDate === todayStr;
      else if (dateFilter === 'upcoming') matchesDate = bookingDate > todayStr;
      else if (dateFilter === 'past') matchesDate = bookingDate < todayStr;

      return matchesSearch && matchesStatus && matchesDate;
    });

    setFilteredBookings(result);
  }, [bookings, search, dateFilter, statusFilter]);

