  useEffect(() => {
    let unsubscribe: Unsubscribe;

    const startListening = (useOrder = true) => {
      console.log(`Starting Firestore listener (orderBy: ${useOrder})...`);
      setLoading(true);
      setError(null);

      try {
        const bookingsCol = collection(db, 'bookings');
        const q = useOrder 
          ? query(bookingsCol, orderBy('createdAt', 'desc'), limit(50))
          : query(bookingsCol, limit(50));

        unsubscribe = onSnapshot(q, (snapshot) => {
          // Debug logs
          console.log("Bookings count (snapshot.size):", snapshot.size);
          if (!snapshot.empty) {
            console.log("First booking doc ID:", snapshot.docs[0].id);
            console.log("First booking raw data:", snapshot.docs[0].data());
          }

          const docs = snapshot.docs.map(doc => ({
            id: doc.id,
            ...doc.data()
          })) as Booking[];

          setBookings(docs);
          setLoading(false);
        }, (err) => {
          console.error("Firestore onSnapshot error:", err);

          // Handle missing index by falling back to unordered query
          if (useOrder && (err.code === 'failed-precondition' || err.message.includes('index'))) {
            console.warn("Index not found. Falling back to unordered query...");
            startListening(false);
          } else {
            setError(`Database error: ${err.message}`);
            setLoading(false);
          }
        });
      } catch (err: any) {
        console.error("Firestore setup error:", err);
        setError(`Setup error: ${err.message}`);
        setLoading(false);
      }
    };

    startListening(true);

    return () => {
      if (unsubscribe) unsubscribe();
    };
  }, []);

  useEffect(() => {
    const now = new Date();
