        bookingRef.toLowerCase().includes(s) || 
        customerEmail.toLowerCase().includes(s) || 
        customerPhone.toLowerCase().includes(s) ||
        customerName.toLowerCase().includes(s);

      // Status logic
      const matchesStatus = statusFilter === 'all' || status === statusFilter;

      // Date logic
      let matchesDate = true;
      if (dateFilter === 'today') matchesDate = dropOffDate === todayStr;
      else if (dateFilter === 'upcoming') matchesDate = dropOffDate > todayStr;
      else if (dateFilter === 'past') matchesDate = dropOffDate < todayStr;

      return matchesSearch && matchesStatus && matchesDate;
    });

    setFilteredBookings(result);
  }, [bookings, search, dateFilter, statusFilter]);

  const handleLogout = () => signOut(auth);

  return (
    <div className="min-h-screen bg-slate-50 pb-12">
      {/* Header */}
      <header className="bg-white border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <img src={logoUrl} alt="Logo" className="h-8 w-auto" />
            <h1 className="font-bold text-lg text-slate-900 hidden sm:block">Admin Console</h1>
          </div>
          <div className="flex items-center gap-4">
            <span className="text-sm text-slate-500 font-medium hidden md:block">{auth.currentUser?.email}</span>
            <button 
              onClick={handleLogout}
              className="text-sm font-semibold text-slate-600 hover:text-red-600 transition-colors px-3 py-1.5 hover:bg-red-50 rounded-lg"
            >
              Sign Out
            </button>
          </div>
        </div>
