              >
                Clear all filters
              </button>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                    <th className="px-6 py-4">Ref</th>
                    <th className="px-6 py-4">Customer</th>
                    <th className="px-6 py-4">Drop-off</th>
                    <th className="px-6 py-4">Bags</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4">Total</th>
                    <th className="px-6 py-4"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filteredBookings.map((booking) => (
                    <tr 
                      key={booking.id} 
                      className="hover:bg-slate-50/80 transition-colors cursor-pointer group"
                      onClick={() => setSelectedBooking(booking)}
                    >
                      <td className="px-6 py-4">
                        <span className="font-mono font-bold text-slate-900">#{booking.bookingRef || 'N/A'}</span>
                        <div className="text-[10px] text-slate-400 uppercase">{booking.bookedOnRome || 'Legacy'}</div>
                      </td>
                      <td className="px-6 py-4">
