                        <p className="text-xs text-slate-500">{booking.customer?.email || '--'}</p>
                      </td>
                      <td className="px-6 py-4">
                        <p className="text-sm font-medium">{booking.dropOff?.date || '--'}</p>
                        <p className="text-xs text-slate-400">{booking.dropOff?.time || '--:--'}</p>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-sm px-2 py-1 bg-slate-100 rounded-md font-medium text-slate-700">
                          {(booking.bags?.small || 0) + (booking.bags?.medium || 0) + (booking.bags?.large || 0)}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <StatusBadge status={booking.status || 'paid'} />
                      </td>
                      <td className="px-6 py-4">
                        <p className="text-sm font-bold text-slate-900">
                          {booking.totalPaid || 0} {(booking.currency || 'EUR').toUpperCase()}
                        </p>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button className="p-2 hover:bg-white border border-transparent hover:border-slate-200 rounded-lg transition-all opacity-0 group-hover:opacity-100 shadow-sm">
