      {selectedBooking && (
        <BookingDetailModal
          booking={selectedBooking}
          onClose={() => setSelectedBooking(null)}
          onUpdate={() => setSelectedBooking(prev => bookings.find(b => b.id === prev?.id) || null)}
        />
      )}
    </div>
  );
};

export default DashboardPage;

