    const bookingRef = db.collection('bookings').doc(session.id);
    await bookingRef.set(bookingData);
    console.log(`✅ Booking data for session ${session.id} saved to Firestore`);
  } catch (error) {
    console.error(`❌ Error saving booking data to Firestore: ${error}`);
  }
}
