type DateFilter = 'all' | 'today' | 'upcoming' | 'past';

const DashboardPage: React.FC = () => {
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [filteredBookings, setFilteredBookings] = useState<Booking[]>([]);
  const [search, setSearch] = useState('');
  const [dateFilter, setDateFilter] = useState<DateFilter>('all');
  const [statusFilter, setStatusFilter] = useState<BookingStatus | 'all'>('all');
  const [selectedBooking, setSelectedBooking] = useState<Booking | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const logoUrl = "https://cdn.shopify.com/s/files/1/0753/8144/0861/files/cropped-Untitled-design-2025-09-11T094640.576_1.png?v=1765462614&width=160&format=webp";

  useEffect(() => {
    let unsubscribe: Unsubscribe;

    const startListening = () => {
      console.log("Initializing Firestore listener for collection: 'bookings'...");
      setLoading(true);
      setError(null);

      try {
        // Task 2: Standard fetch query (requires index on createdAt)
        const bookingsCol = collection(db, 'bookings');
        const q = query(bookingsCol, orderBy('createdAt', 'desc'), limit(50));

        unsubscribe = onSnapshot(q, (snapshot) => {
          // Task 4: Debug logs
          console.log("Firestore Snapshot received.");
          console.log("Bookings count (snapshot.size):", snapshot.size);

          if (!snapshot.empty) {
            console.log("First booking doc ID:", snapshot.docs[0].id);
            console.log("First booking raw data sample:", snapshot.docs[0].data());
          } else {
            console.warn("Snapshot is empty. Ensure documents exist in the 'bookings' collection.");
          }

          const docs = snapshot.docs.map(doc => ({
            id: doc.id,
            ...doc.data()
          })) as Booking[];

          setBookings(docs);
          setLoading(false);
        }, (err) => {
          // Task 3: Visible error handling
          console.error("Firestore Error:", err);

          // Fallback if index is missing (common cause for dashboard being empty silently)
          if (err.message.includes("requires an index")) {
             console.warn("Index missing. Retrying with unordered query for debug...");
             const fallbackQ = query(collection(db, 'bookings'), limit(50));
             onSnapshot(fallbackQ, (fallbackSnapshot) => {
                const docs = fallbackSnapshot.docs.map(doc => ({
                  id: doc.id,
                  ...doc.data()
                })) as Booking[];
                setBookings(docs);
                setLoading(false);
                setError("Warning: Showing unordered results. Firestore index for 'createdAt' is still building.");
             });
          } else {
            setError(`Database Access Error: ${err.message}. Please check Firestore rules and collection names.`);
            setLoading(false);
          }
        });
      } catch (err: any) {
        console.error("Setup error:", err);
        setError(`Application Error: ${err.message}`);
        setLoading(false);
      }
    };

    startListening();

    return () => {
      if (unsubscribe) unsubscribe();
    };
  }, []);

  useEffect(() => {
    const now = new Date();
    const todayStr = now.toISOString().split('T')[0];

    // Task 6: Reintroduce filters with safe field access
    let result = bookings.filter(b => {
      const bRef = (b.bookingRef || '').toLowerCase();
      const cName = (b.customer?.name || '').toLowerCase();
      const cEmail = (b.customer?.email || '').toLowerCase();
      const cPhone = (b.customer?.phone || '').toLowerCase();
      const bStatus = b.status || 'paid';
      const dropDate = b.dropOff?.date || '';

      // Search
      const s = search.toLowerCase();
      const matchesSearch = !search || 
        bRef.includes(s) || 
        cName.includes(s) || 
        cEmail.includes(s) || 
        cPhone.includes(s);

      // Status
      const matchesStatus = statusFilter === 'all' || bStatus === statusFilter;

      // Date
      let matchesDate = true;
      if (dateFilter === 'today') matchesDate = dropDate === todayStr;
      else if (dateFilter === 'upcoming') matchesDate = dropDate > todayStr;
      else if (dateFilter === 'past') matchesDate = dropDate < todayStr;

      return matchesSearch && matchesStatus && matchesDate;
    });

    setFilteredBookings(result);
  }, [bookings, search, dateFilter, statusFilter]);

  const handleLogout = () => signOut(auth);

  return (
    <div className="min-h-screen bg-slate-50 pb-12">
      {/* Header */}
      <header className="bg-white border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
