  useEffect(() => {
    let unsubscribe: Unsubscribe;

    const startListening = () => {
      setLoading(true);
      setError(null);

      try {
        // Query plural 'bookings' collection
        const bookingsCol = collection(db, 'bookings');
        const q = query(bookingsCol, orderBy('createdAt', 'desc'), limit(100));

        unsubscribe = onSnapshot(q, (snapshot) => {
          const docs = snapshot.docs.map(doc => {
            const data = doc.data();
            // Safe mapping to prevent crashes from missing fields
            return {
              id: doc.id,
              bookingRef: data.bookingRef || 'N/A',
              stripeSessionId: data.stripeSessionId || '',
              createdAt: data.createdAt,
              bookedOnRome: data.bookedOnRome || '',
              customer: {
                name: data.customer?.name || 'Unknown',
                email: data.customer?.email || 'N/A',
                phone: data.customer?.phone || 'N/A'
              },
              dropOff: {
                date: data.dropOff?.date || '',
                time: data.dropOff?.time || '',
                datetime: data.dropOff?.datetime
              },
              pickUp: {
                date: data.pickUp?.date || '',
                time: data.pickUp?.time || '',
                datetime: data.pickUp?.datetime
              },
              billableDays: data.billableDays || 0,
              bags: {
                small: data.bags?.small || 0,
                medium: data.bags?.medium || 0,
                large: data.bags?.large || 0
              },
              totalPaid: data.totalPaid || 0,
              currency: data.currency || 'eur',
