import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { onAuthStateChanged, type User } from 'firebase/auth';
import { doc, getDoc } from 'firebase/firestore';
import { auth, db } from './firebase';
import LoginPage from './pages/LoginPage';
import DashboardPage from './pages/DashboardPage';
import UnauthorizedPage from './pages/UnauthorizedPage';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [isAdmin, setIsAdmin] = useState<boolean | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Single source of truth for auth state
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      setLoading(true);
      if (currentUser) {
        try {
          const email = currentUser.email?.toLowerCase() || '';
          const adminDoc = await getDoc(doc(db, 'admins', email));

          if (adminDoc.exists() && adminDoc.data().active === true) {
            setUser(currentUser);
            setIsAdmin(true);
          } else {
            setUser(currentUser);
            setIsAdmin(false);
          }
        } catch (error) {
          console.error("Admin verification failed:", error);
          setUser(currentUser);
          setIsAdmin(false);
        }
      } else {
        setUser(null);
        setIsAdmin(null);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  if (loading) {
    return (
      <div className="flex h-screen items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center gap-4">
          <div className="h-10 w-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-slate-500 font-medium animate-pulse">Checking Permissions...</p>
        </div>
      </div>
    );
  }

  return (
    <HashRouter>
      <Routes>
        <Route 
          path="/login" 
          element={user ? (isAdmin ? <Navigate to="/" /> : <Navigate to="/unauthorized" />) : <LoginPage />} 
        />
        <Route 
          path="/unauthorized" 
          element={user && isAdmin === false ? <UnauthorizedPage /> : <Navigate to="/" />} 
        />
        <Route 
          path="/" 
          element={user && isAdmin === true ? <DashboardPage /> : <Navigate to="/login" />} 
        />
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </HashRouter>
  );
};

export default App;

