                      <td className="px-6 py-4">
                        <p className="font-bold text-slate-900">{booking.totalPaid} {booking.currency.toUpperCase()}</p>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button className="opacity-0 group-hover:opacity-100 p-2 hover:bg-white border border-transparent hover:border-slate-200 rounded-lg transition-all">
                          <svg className="w-5 h-5 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </main>

      {selectedBooking && (
        <BookingDetailModal
          booking={selectedBooking}
          onClose={() => setSelectedBooking(null)}
          onUpdate={() => {
            // Trigger local state update logic if needed or just let onSnapshot handle it
          }}
        />
      )}
    </div>
  );
};

