import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { onAuthStateChanged, type User } from 'firebase/auth';
import { doc, getDoc } from 'firebase/firestore';
import { auth, db } from './firebase';
import LoginPage from './pages/LoginPage';
import DashboardPage from './pages/DashboardPage';
import UnauthorizedPage from './pages/UnauthorizedPage';
import ScanPage from './pages/ScanPage';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [isAdmin, setIsAdmin] = useState<boolean | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      setLoading(true);
      if (currentUser) {
        try {
          const adminDoc = await getDoc(doc(db, 'admins', currentUser.email || ''));
          if (adminDoc.exists() && adminDoc.data().active === true) {
            setUser(currentUser);
            setIsAdmin(true);
          } else {
            setUser(currentUser);
            setIsAdmin(false);
          }
        } catch (error) {
          console.error("Error verifying admin status:", error);
          setUser(currentUser);
          setIsAdmin(false);
        }
      } else {
        setUser(null);
        setIsAdmin(null);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  if (loading) {
    return (
      <div className="flex h-screen items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center space-y-4">
          <div className="h-12 w-12 animate-spin rounded-full border-4 border-blue-600 border-t-transparent"></div>
          <p className="text-slate-500 font-medium tracking-wide">Securing connection...</p>
        </div>
      </div>
    );
  }

  return (
    <HashRouter>
      <Routes>
        <Route 
          path="/login" 
          element={user ? (isAdmin ? <Navigate to="/" /> : <Navigate to="/unauthorized" />) : <LoginPage />} 
        />
        <Route 
          path="/unauthorized" 
          element={user && !isAdmin ? <UnauthorizedPage /> : <Navigate to="/" />} 
        />
        <Route 
          path="/" 
          element={user && isAdmin ? <DashboardPage /> : <Navigate to="/login" />} 
        />
        <Route 
          path="/scan" 
          element={user && isAdmin ? <ScanPage /> : <Navigate to="/login" />} 
        />
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </HashRouter>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { Html5Qrcode } from 'html5-qrcode';
import { auth } from '../firebase';

interface BookingSummary {
  id: string;
  bookingRef: string;
  customer: {
    name: string;
    email: string;
    phone: string;
  };
  bags: {
    small: number;
    medium: number;
    large: number;
  };
  dropOff: {
    date: string;
    time: string;
  };
  status: string;
}

const ScanPage: React.FC = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const [isScanning, setIsScanning] = useState(false);
  const [token, setToken] = useState<string | null>(searchParams.get('token'));
  const [booking, setBooking] = useState<BookingSummary | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);
  const scannerRef = useRef<Html5Qrcode | null>(null);

  useEffect(() => {
    if (token) {
      verifyToken(token);
    }
    return () => {
      stopScanner();
    };
  }, [token]);

  const verifyToken = async (jwtToken: string) => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch('/api/checkin/verify', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token: jwtToken }),
      });
      const data = await response.json();
      if (response.ok) {
        setBooking(data.booking);
      } else {
        setError(data.error || 'Invalid or expired QR code.');
      }
    } catch (err) {
      setError('Network error verifying code.');
    } finally {
      setLoading(false);
    }
  };

  const handleConfirmCheckIn = async () => {
    if (!token || !booking) return;
    setLoading(true);
    try {
      const response = await fetch('/api/checkin/confirm', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          token,
          adminEmail: auth.currentUser?.email 
        }),
      });
      if (response.ok) {
        setSuccess(true);
        setTimeout(() => navigate('/'), 2000);
      } else {
        const data = await response.json();
        setError(data.error || 'Failed to confirm check-in.');
      }
    } catch (err) {
      setError('Network error during check-in.');
    } finally {
      setLoading(false);
    }
  };

  const startScanner = async () => {
    setIsScanning(true);
    setError(null);
    const html5QrCode = new Html5Qrcode("reader");
    scannerRef.current = html5QrCode;

    try {
      await html5QrCode.start(
        { facingMode: "environment" },
        { fps: 10, qrbox: { width: 250, height: 250 } },
        (decodedText) => {
          // Check if decoded text is a full URL or just the token
          let extractedToken = decodedText;
          if (decodedText.includes('token=')) {
            extractedToken = new URL(decodedText.replace('#/', '')).searchParams.get('token') || decodedText;
          }
          setToken(extractedToken);
          stopScanner();
        },
        () => {} // Ignored errors
      );
    } catch (err) {
      setError("Unable to access camera.");
      setIsScanning(false);
    }
  };

  const stopScanner = async () => {
    if (scannerRef.current && scannerRef.current.isScanning) {
      await scannerRef.current.stop();
      setIsScanning(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-8">
      <div className="max-w-xl mx-auto">
        <button 
          onClick={() => navigate('/')}
          className="mb-6 flex items-center text-slate-500 hover:text-slate-900 font-medium"
        >
          <svg className="w-5 h-5 mr-1" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
          Back to Dashboard
        </button>

        <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 border-b border-slate-50 bg-slate-50/50">
            <h1 className="text-2xl font-bold text-slate-900">QR Check-in</h1>
            <p className="text-slate-500 text-sm">Scan customer code to verify booking</p>
          </div>

          <div className="p-8">
            {success ? (
              <div className="text-center py-12 space-y-4">
                <div className="inline-flex items-center justify-center w-20 h-20 bg-emerald-100 rounded-full text-emerald-600">
                  <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                </div>
                <h2 className="text-2xl font-bold text-slate-900">Check-in Complete!</h2>
                <p className="text-slate-500">Redirecting to dashboard...</p>
              </div>
            ) : booking ? (
              <div className="space-y-6">
                <div className="flex justify-between items-start">
                  <div>
                    <span className="text-xs font-bold uppercase tracking-widest text-blue-600">Booking Reference</span>
                    <h2 className="text-3xl font-black text-slate-900">#{booking.bookingRef}</h2>
                  </div>
                  <div className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${booking.status === 'paid' ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'}`}>
                    {booking.status.replace('_', ' ')}
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-6 bg-slate-50 p-6 rounded-2xl">
                  <div>
                    <p className="text-xs font-semibold text-slate-400 uppercase mb-1">Customer</p>
                    <p className="font-bold text-slate-900">{booking.customer.name}</p>
                    <p className="text-sm text-slate-500">{booking.customer.phone}</p>
                  </div>
                  <div>
                    <p className="text-xs font-semibold text-slate-400 uppercase mb-1">Drop-off</p>
                    <p className="font-bold text-slate-900">{booking.dropOff.date}</p>
                    <p className="text-sm text-slate-500">at {booking.dropOff.time}</p>
                  </div>
                  <div className="col-span-2 pt-2 border-t border-slate-200">
                    <p className="text-xs font-semibold text-slate-400 uppercase mb-2">Items to Deposit</p>
                    <div className="flex gap-4">
                      {booking.bags.small > 0 && <span className="text-sm font-medium">Small: {booking.bags.small}</span>}
                      {booking.bags.medium > 0 && <span className="text-sm font-medium">Medium: {booking.bags.medium}</span>}
                      {booking.bags.large > 0 && <span className="text-sm font-medium">Large: {booking.bags.large}</span>}
                    </div>
                  </div>
                </div>

                {booking.status === 'checked_in' ? (
                  <div className="p-4 bg-blue-50 text-blue-700 rounded-xl text-center font-semibold">
                    This booking is already checked in.
                  </div>
                ) : (
                  <button
                    onClick={handleConfirmCheckIn}
                    disabled={loading}
                    className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold text-lg hover:bg-blue-700 shadow-lg shadow-blue-200 transition-all disabled:opacity-50"
                  >
                    {loading ? 'Processing...' : 'Confirm Check-in'}
                  </button>
                )}

                <button 
                  onClick={() => { setBooking(null); setToken(null); navigate('/scan'); }}
                  className="w-full text-slate-400 font-medium text-sm hover:text-slate-600"
                >
                  Scan different code
                </button>
              </div>
            ) : (
              <div className="space-y-6">
                <div id="reader" className={`${isScanning ? 'block' : 'hidden'} overflow-hidden rounded-2xl bg-black aspect-square`}></div>

                {!isScanning && (
                  <div className="text-center py-10">
                    <div className="w-20 h-20 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
                      <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" /></svg>
                    </div>
                    <h2 className="text-xl font-bold text-slate-900 mb-2">Ready to Scan</h2>
                    <p className="text-slate-500 mb-8 px-4 text-sm">Scan the QR code from the customer's confirmation email to begin.</p>

                    <button
                      onClick={startScanner}
                      className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold text-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-2"
                    >
                      <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                      Open Camera
                    </button>
                  </div>
                )}

                {loading && <div className="text-center text-slate-400">Verifying code...</div>}

                {error && (
                  <div className="p-4 bg-red-50 text-red-600 rounded-xl text-sm font-medium border border-red-100 flex items-center gap-2">
                    <svg className="w-5 h-5 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                    {error}
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

