    const bookingDocRef = bookingSnap.docs[0].ref;

    await bookingDocRef.update({
      status: 'checked_in',
      checkedInAt: FieldValue.serverTimestamp(),
      updatedAt: FieldValue.serverTimestamp(),
      checkedInBy: adminEmail || 'unknown_admin'
    });

