import React, { useState, useEffect, useMemo } from 'react';
import { collection, getDocs, query, orderBy } from 'firebase/firestore';
import { useNavigate, Link } from 'react-router-dom';
import { auth, db } from '../firebase';
import { Booking } from '../types';
import { signOut } from 'firebase/auth';

type ReportMode = 'day' | 'month' | 'year';

const ReportsPage: React.FC = () => {
  const navigate = useNavigate();
  const [activeBookings, setActiveBookings] = useState<Booking[]>([]);
  const [archivedBookings, setArchivedBookings] = useState<Booking[]>([]);
  const [loading, setLoading] = useState(true);
  const [mode, setMode] = useState<ReportMode>('month');
  const [selectedDate, setSelectedDate] = useState(() => {
    const d = new Date();
    return d.toISOString().split('T')[0].substring(0, 7); // Default to current month YYYY-MM
  });

  const [archiveStatus, setArchiveStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});
  const [archiving, setArchiving] = useState(false);

  const logoUrl = "https://cdn.shopify.com/s/files/1/0753/8144/0861/files/cropped-Untitled-design-2025-09-11T094640.576_1.png?v=1765462614&width=160&format=webp";

  const fetchAllData = async () => {
    setLoading(true);
    try {
      const qActive = query(collection(db, "bookings"), orderBy("createdAt", "desc"));
      const qArchive = query(collection(db, "bookings_archive"), orderBy("createdAt", "desc"));

      const [snapActive, snapArchive] = await Promise.all([
        getDocs(qActive),
        getDocs(qArchive)
      ]);

      const mapDocs = (snapshot: any) => snapshot.docs.map((d: any) => {
        const data: any = d.data();
        return {
          id: d.id,
          bookingRef: String(data.bookingRef ?? ""),
          stripeSessionId: String(data.stripeSessionId ?? ""),
          createdAt: data.createdAt ?? null,
          archivedAt: data.archivedAt ?? null,
          bookedOnRome: "",
          customer: data.customer,
          dropOff: data.dropOff,
          pickUp: data.pickUp,
          billableDays: Number(data.billableDays ?? 0),
          bags: data.bags,
          totalPaid: Number(data.totalPaid ?? 0),
          currency: String(data.currency ?? "EUR"),
          status: data.status,
          notes: data.notes ?? "",
          walletIssued: Boolean(data.walletIssued ?? false),
        };
      });

      setActiveBookings(mapDocs(snapActive));
      setArchivedBookings(mapDocs(snapArchive));
    } catch (err) {
      console.error("Error fetching report data:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAllData();
  }, []);

  const bookings = useMemo(() => [...activeBookings, ...archivedBookings], [activeBookings, archivedBookings]);

  const stats = useMemo(() => {
    const filtered = bookings.filter(b => {
      const bDate = b.dropOff.date; // Filtering by dropOff date for revenue reporting
      if (mode === 'day') return bDate === selectedDate;
      if (mode === 'month') return bDate.startsWith(selectedDate);
      if (mode === 'year') return bDate.startsWith(selectedDate.substring(0, 4));
      return false;
    });

    const totalBookings = filtered.length;
    const revenue = filtered.reduce((acc, b) => b.status !== 'cancelled' ? acc + b.totalPaid : acc, 0);

    const byStatus = {
      paid: filtered.filter(b => b.status === 'paid').length,
      checked_in: filtered.filter(b => b.status === 'checked_in').length,
      picked_up: filtered.filter(b => b.status === 'picked_up').length,
      cancelled: filtered.filter(b => b.status === 'cancelled').length,
    };

    return { totalBookings, revenue, byStatus };
  }, [bookings, mode, selectedDate]);

  const handleArchiveAll = async () => {
    if (!window.confirm("Archive all checked-out bookings older than 7 days?")) return;

    setArchiving(true);
    setArchiveStatus({message: '', type: null});

    try {
      const response = await fetch('/api/archive/picked-up', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ days: 7 })
      });

      const data = await response.json();
      if (response.ok) {
        setArchiveStatus({message: `Success! Archived ${data.count} bookings.`, type: 'success'});
        fetchAllData(); // Refresh list
      } else {
        setArchiveStatus({message: data.error || 'Archive failed.', type: 'error'});
      }
    } catch (err) {
      setArchiveStatus({message: 'Network error.', type: 'error'});
    } finally {
      setArchiving(false);
    }
  };

  const handleLogout = () => signOut(auth);

  return (
    <div className="min-h-screen bg-slate-50 pb-12 overflow-x-hidden">
      <header className="bg-white border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Link to="/"><img src={logoUrl} alt="Logo" className="h-8 w-auto" /></Link>
            <h1 className="font-bold text-lg text-slate-900 hidden sm:block">Admin Reports</h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden md:flex items-center gap-4 mr-4 border-r pr-4 border-slate-200">
               <Link to="/" className="text-sm font-bold text-slate-500 hover:text-blue-600 transition-colors">Bookings</Link>
               <Link to="/reports" className="text-sm font-bold text-blue-600">Reports</Link>
            </div>
            <button onClick={handleLogout} className="text-sm font-semibold text-slate-600 hover:text-red-600 transition-colors px-3 py-1.5 hover:bg-red-50 rounded-lg">Sign Out</button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 mt-6">
        <div className="mb-8">
            <h2 className="text-2xl font-bold text-slate-900">Performance Stats</h2>
            <p className="text-slate-500">Analyze combined revenue from active and archived bookings</p>
        </div>

        {/* Report Filters */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
           <div className="flex bg-white p-1.5 rounded-2xl border border-slate-200 shadow-sm w-fit">
              {(['day', 'month', 'year'] as const).map(m => (
                <button
                  key={m}
                  onClick={() => {
                    setMode(m);
                    if (m === 'year') setSelectedDate(new Date().getFullYear().toString());
                    else if (m === 'month') setSelectedDate(new Date().toISOString().substring(0, 7));
                    else setSelectedDate(new Date().toISOString().substring(0, 10));
                  }}
                  className={`px-6 py-2 text-sm font-bold rounded-xl transition-all capitalize ${mode === m ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'text-slate-500 hover:text-slate-900'}`}
                >
                  {m}
                </button>
              ))}
           </div>

           <div className="flex items-center gap-3">
              <input 
                type={mode === 'day' ? 'date' : mode === 'month' ? 'month' : 'number'}
                className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 font-bold outline-none focus:ring-2 focus:ring-blue-500 shadow-sm"
                value={selectedDate}
                min={mode === 'year' ? 2024 : undefined}
                max={mode === 'year' ? 2030 : undefined}
                onChange={(e) => setSelectedDate(e.target.value)}
              />
              <span className="text-slate-400 text-xs font-bold uppercase tracking-widest">Selected Period</span>
           </div>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
           <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Total Revenue</p>
              <p className="text-4xl font-black text-emerald-600">{stats.revenue.toLocaleString()} EUR</p>
              <p className="text-xs text-slate-400 mt-2">Combined active & archived</p>
           </div>
           <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Total Bookings</p>
              <p className="text-4xl font-black text-slate-900">{stats.totalBookings}</p>
              <p className="text-xs text-slate-400 mt-2">Historical volume total</p>
           </div>
           <div className="bg-slate-900 p-8 rounded-3xl text-white shadow-xl shadow-slate-200">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Avg. Per Booking</p>
              <p className="text-4xl font-black">{stats.totalBookings > 0 ? (stats.revenue / stats.totalBookings).toFixed(2) : '0'} <span className="text-lg opacity-50">EUR</span></p>
              <p className="text-xs text-slate-500 mt-2">Revenue / Bookings ratio</p>
           </div>
        </div>

        {/* Status Breakdown */}
        <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden mb-12">
           <div className="p-6 border-b border-slate-50">
              <h3 className="font-bold text-slate-900">Status Distribution (Combined)</h3>
           </div>
           <div className="grid grid-cols-2 md:grid-cols-4 divide-x divide-slate-50">
              <div className="p-8 text-center">
                 <p className="text-2xl font-black text-emerald-600">{stats.byStatus.paid}</p>
                 <p className="text-[10px] font-bold text-slate-400 uppercase">Paid</p>
              </div>
              <div className="p-8 text-center">
                 <p className="text-2xl font-black text-blue-600">{stats.byStatus.checked_in}</p>
                 <p className="text-[10px] font-bold text-slate-400 uppercase">In Storage</p>
              </div>
              <div className="p-8 text-center">
                 <p className="text-2xl font-black text-slate-800">{stats.byStatus.picked_up}</p>
                 <p className="text-[10px] font-bold text-slate-400 uppercase">Picked Up</p>
              </div>
              <div className="p-8 text-center">
                 <p className="text-2xl font-black text-red-500">{stats.byStatus.cancelled}</p>
                 <p className="text-[10px] font-bold text-slate-400 uppercase">Cancelled</p>
              </div>
           </div>
        </div>

        {/* Maintenance Section */}
        <div className="bg-orange-50 border border-orange-100 rounded-3xl p-8">
           <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
              <div className="max-w-lg">
                 <h3 className="text-orange-900 font-bold text-lg mb-1">Database Maintenance</h3>
                 <p className="text-orange-700 text-sm">Archiving is now immediate on checkout. Use this tool only to catch up on legacy data in the active collection.</p>
              </div>
              <div>
                 <button 
                  onClick={handleArchiveAll}
                  disabled={archiving}
                  className="px-8 py-4 bg-orange-600 text-white rounded-2xl font-bold hover:bg-orange-700 transition-all disabled:opacity-50 shadow-lg shadow-orange-200 whitespace-nowrap"
                 >
                    {archiving ? 'Archiving...' : 'Run Catch-up Archive'}
                 </button>
              </div>
           </div>
           {archiveStatus.type && (
             <div className={`mt-4 p-4 rounded-xl text-sm font-bold ${archiveStatus.type === 'success' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                {archiveStatus.message}
             </div>
           )}
        </div>
      </main>
    </div>
  );
};

export default ReportsPage;

import React, { useState, useEffect, useMemo } from 'react';
import { collection, query, orderBy, onSnapshot } from 'firebase/firestore';
import { signOut } from 'firebase/auth';
import { useNavigate, Link } from 'react-router-dom';
import { auth, db } from '../firebase';
import { Booking, BookingStatus } from '../types';
import StatusBadge from '../components/StatusBadge';
import BookingDetailModal from '../components/BookingDetailModal';

type DateFilter = 'all' | 'today' | 'upcoming' | 'past';
type ViewMode = 'active' | 'archived';

const DashboardPage: React.FC = () => {
  const navigate = useNavigate();
  const [viewMode, setViewMode] = useState<ViewMode>('active');
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [search, setSearch] = useState('');
  const [dateFilter, setDateFilter] = useState<DateFilter>('all');
  const [statusFilter, setStatusFilter] = useState<BookingStatus | 'all'>('all');
  const [selectedBookingId, setSelectedBookingId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  const logoUrl = "https://cdn.shopify.com/s/files/1/0753/8144/0861/files/cropped-Untitled-design-2025-09-11T094640.576_1.png?v=1765462614&width=160&format=webp";

  const selectedBooking = useMemo(() => 
    bookings.find(b => b.id === selectedBookingId) || null,
    [bookings, selectedBookingId]
  );

  useEffect(() => {
    setLoading(true);
    const collectionName = viewMode === 'active' ? "bookings" : "bookings_archive";
    // Fix 1: Use archivedAt for archive mode ordering
    const sortField = viewMode === 'active' ? "createdAt" : "archivedAt";
    const q = query(collection(db, collectionName), orderBy(sortField, "desc"));

    const unsubscribe = onSnapshot(
      q,
      (snapshot) => {
        const docs: Booking[] = snapshot.docs.map((d) => {
          const data: any = d.data();
          // Safe defensive mapping
          return {
            id: d.id,
            bookingRef: String(data.bookingRef ?? ""),
            stripeSessionId: String(data.stripeSessionId ?? ""),
            createdAt: data.createdAt ?? null,
            archivedAt: data.archivedAt ?? null,
            bookedOnRome: "",
            customer: {
              name: String(data.customer?.name ?? ""),
              email: String(data.customer?.email ?? ""),
              phone: String(data.customer?.phone ?? ""),
            },
            dropOff: {
              date: String(data.dropOff?.date ?? ""),
              time: String(data.dropOff?.time ?? ""),
              datetime: data.dropOff?.datetime ?? null,
            },
            pickUp: {
              date: String(data.pickUp?.date ?? ""),
              time: String(data.pickUp?.time ?? ""),
              datetime: data.pickUp?.datetime ?? null,
            },
            billableDays: Number(data.billableDays ?? 0),
            bags: {
              small: Number(data.bags?.small ?? 0),
              medium: Number(data.bags?.medium ?? 0),
              large: Number(data.bags?.large ?? 0),
            },
            totalPaid: Number(data.totalPaid ?? 0),
            currency: String(data.currency ?? "EUR"),
            status: (data.status ?? "paid") as any,
            notes: String(data.notes ?? data.dropOff?.notes ?? ""),
            walletIssued: Boolean(data.walletIssued ?? false),
          };
        });

        setBookings(docs);
        setLoading(false);
      },
      (err) => {
        console.error(`Firestore ${collectionName} snapshot error:`, err);
        setBookings([]);
        setLoading(false);
      }
    );

    return () => unsubscribe();
  }, [viewMode]);

  const filteredBookings = useMemo(() => {
    const now = new Date();
    const todayStr = now.toISOString().split('T')[0];

    return bookings.filter(b => {
      const s = search.toLowerCase();
      const matchesSearch = !search || 
        b.bookingRef.toLowerCase().includes(s) || 
        b.customer.email.toLowerCase().includes(s) || 
        b.customer.phone.toLowerCase().includes(s) ||
        b.customer.name.toLowerCase().includes(s);

      const matchesStatus = statusFilter === 'all' || b.status === statusFilter;

      const bookingDate = b.dropOff.date;
      let matchesDate = true;
      if (dateFilter === 'today') matchesDate = bookingDate === todayStr;
      else if (dateFilter === 'upcoming') matchesDate = bookingDate > todayStr;
      else if (dateFilter === 'past') matchesDate = bookingDate < todayStr;

      return matchesSearch && matchesStatus && matchesDate;
    });
  }, [bookings, search, dateFilter, statusFilter]);

  const handleLogout = () => signOut(auth);

  return (
    <div className="min-h-screen bg-slate-50 pb-12 overflow-x-hidden">
      <header className="bg-white border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <img src={logoUrl} alt="Logo" className="h-8 w-auto" />
            <h1 className="font-bold text-lg text-slate-900 hidden sm:block">Admin Console</h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden md:flex items-center gap-4 mr-4 border-r pr-4 border-slate-200">
               <Link to="/" className="text-sm font-bold text-blue-600">Bookings</Link>
               <Link to="/reports" className="text-sm font-bold text-slate-500 hover:text-blue-600 transition-colors">Reports</Link>
            </div>
            <button 
              onClick={() => navigate('/scan')}
              className="hidden sm:flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-xl text-sm font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-200"
            >
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" /></svg>
              <span>Scan QR</span>
            </button>
            <button 
              onClick={handleLogout}
              className="text-sm font-semibold text-slate-600 hover:text-red-600 transition-colors px-3 py-1.5 hover:bg-red-50 rounded-lg"
            >
              Sign Out
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 mt-6">
        <div className="sm:hidden mb-6 flex flex-col gap-3">
          <button 
            onClick={() => navigate('/scan')}
            className="w-full flex items-center justify-center gap-3 py-5 bg-blue-600 text-white rounded-2xl text-xl font-black shadow-xl shadow-blue-200 active:scale-[0.98] transition-all"
          >
            <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" /></svg>
            <span>Scan QR Code</span>
          </button>
          <Link to="/reports" className="w-full text-center py-3 bg-white border border-slate-200 rounded-xl font-bold text-slate-600 text-sm">View Stats & Reports</Link>
        </div>

        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6 mb-8">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <h2 className="text-2xl font-bold text-slate-900">Bookings</h2>
              <span className={`text-[10px] font-black uppercase px-2 py-0.5 rounded ${viewMode === 'active' ? 'bg-emerald-100 text-emerald-600' : 'bg-orange-100 text-orange-600'}`}>
                {viewMode}
              </span>
            </div>
            <p className="text-slate-500">Track and update luggage storage requests</p>
          </div>

          <div className="flex flex-col sm:flex-row gap-4">
            <div className="flex bg-white p-1 rounded-xl border border-slate-200 shadow-sm">
              <button 
                onClick={() => setViewMode('active')}
                className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all ${viewMode === 'active' ? 'bg-slate-900 text-white' : 'text-slate-400 hover:text-slate-600'}`}
              >
                Active
              </button>
              <button 
                onClick={() => setViewMode('archived')}
                className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all ${viewMode === 'archived' ? 'bg-slate-900 text-white' : 'text-slate-400 hover:text-slate-600'}`}
              >
                Archived
              </button>
            </div>
            <div className="relative">
              <input
                type="text"
                placeholder="Ref, Email, Phone..."
                className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 w-full sm:w-64 transition-all"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
              <svg className="w-5 h-5 absolute left-3 top-2.5 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </div>
          </div>
        </div>

        <div className="flex flex-wrap gap-2 mb-6">
          <div className="flex bg-white p-1 rounded-xl border border-slate-200 shadow-sm overflow-x-auto max-w-full hide-scrollbar">
            {(['all', 'today', 'upcoming', 'past'] as const).map((f) => (
              <button
                key={f}
                onClick={() => setDateFilter(f)}
                className={`whitespace-nowrap px-4 py-1.5 text-xs font-semibold rounded-lg transition-all capitalize ${dateFilter === f ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'}`}
              >
                {f}
              </button>
            ))}
          </div>
          <div className="flex bg-white p-1 rounded-xl border border-slate-200 shadow-sm overflow-x-auto max-w-full hide-scrollbar">
            {(['all', 'paid', 'checked_in', 'picked_up', 'cancelled'] as const).map((s) => (
              <button
                key={s}
                onClick={() => setStatusFilter(s)}
                className={`whitespace-nowrap px-4 py-1.5 text-xs font-semibold rounded-lg transition-all capitalize ${statusFilter === s ? 'bg-slate-800 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'}`}
              >
                {s.replace('_', ' ')}
              </button>
            ))}
          </div>
        </div>

        <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
          {loading ? (
            <div className="p-20 text-center text-slate-400">Loading {viewMode} bookings...</div>
          ) : filteredBookings.length === 0 ? (
            <div className="p-20 text-center">
              <p className="text-slate-500 mb-2">No {viewMode} bookings found matching your criteria</p>
              <button onClick={() => { setSearch(''); setDateFilter('all'); setStatusFilter('all'); }} className="text-blue-600 font-semibold text-sm underline">Clear all filters</button>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                    <th className="px-4 py-4 md:px-6">Ref</th>
                    <th className="px-4 py-4 md:px-6">Customer</th>
                    <th className="hidden md:table-cell px-6 py-4">Drop-off</th>
                    <th className="hidden sm:table-cell px-6 py-4">Bags</th>
                    <th className="hidden md:table-cell px-6 py-4">Status</th>
                    <th className="px-4 py-4 md:px-6">Total</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filteredBookings.map((booking) => (
                    <tr 
                      key={booking.id} 
                      className="hover:bg-slate-50/80 transition-colors cursor-pointer group"
                      onClick={() => setSelectedBookingId(booking.id)}
                    >
                      <td className="px-4 py-4 md:px-6 align-top">
                        <span className="font-mono font-bold text-slate-900 block">#{booking.bookingRef}</span>
                        <div className="md:hidden mt-2 flex flex-col gap-1.5 items-start">
                          <StatusBadge status={booking.status} />
                          <p className="text-[10px] text-slate-500 font-medium">
                            {booking.dropOff.date} {booking.dropOff.time}
                          </p>
                        </div>
                      </td>
                      <td className="px-4 py-4 md:px-6 align-top">
                        <p className="font-semibold text-slate-900 text-sm truncate max-w-[100px] sm:max-w-none">{booking.customer.name}</p>
                        <p className="text-[10px] text-slate-400 hidden sm:block">{booking.customer.email}</p>
                      </td>
                      <td className="hidden md:table-cell px-6 py-4 align-top">
                        <p className="text-sm font-medium">{booking.dropOff.date}</p>
                        <p className="text-xs text-slate-400">{booking.dropOff.time}</p>
                      </td>
                      <td className="hidden sm:table-cell px-6 py-4 align-top">
                        <span className="text-xs px-2 py-0.5 bg-slate-100 rounded-md font-medium text-slate-700">
                          {booking.bags.small + booking.bags.medium + booking.bags.large}
                        </span>
                      </td>
                      <td className="hidden md:table-cell px-6 py-4 align-top">
                        <StatusBadge status={booking.status} />
                      </td>
                      <td className="px-4 py-4 md:px-6 font-bold text-slate-900 text-sm align-top">
                        {booking.totalPaid} {booking.currency.toUpperCase()}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </main>

      {selectedBooking && (
        <BookingDetailModal
          booking={selectedBooking}
          onClose={() => setSelectedBookingId(null)}
          onUpdate={() => {}}
        />
      )}
    </div>
  );
};

export default DashboardPage;

import React, { useState, useEffect, useMemo } from 'react';
import { collection, getDocs, query, orderBy } from 'firebase/firestore';
import { useNavigate, Link } from 'react-router-dom';
import { auth, db } from '../firebase';
import { Booking } from '../types';
import { signOut } from 'firebase/auth';

type ReportMode = 'day' | 'month' | 'year';

const ReportsPage: React.FC = () => {
  const navigate = useNavigate();
  const [activeBookings, setActiveBookings] = useState<Booking[]>([]);
  const [archivedBookings, setArchivedBookings] = useState<Booking[]>([]);
  const [loading, setLoading] = useState(true);
  const [mode, setMode] = useState<ReportMode>('month');
  const [selectedDate, setSelectedDate] = useState(() => {
    const d = new Date();
    return d.toISOString().split('T')[0].substring(0, 7); // Default to current month YYYY-MM
  });

  const [archiveStatus, setArchiveStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});
  const [archiving, setArchiving] = useState(false);

  const logoUrl = "https://cdn.shopify.com/s/files/1/0753/8144/0861/files/cropped-Untitled-design-2025-09-11T094640.576_1.png?v=1765462614&width=160&format=webp";

  const fetchAllData = async () => {
    setLoading(true);
    try {
      const qActive = query(collection(db, "bookings"), orderBy("createdAt", "desc"));
      const qArchive = query(collection(db, "bookings_archive"), orderBy("createdAt", "desc"));

      const [snapActive, snapArchive] = await Promise.all([
        getDocs(qActive),
        getDocs(qArchive)
      ]);

      const mapDocs = (snapshot: any) => snapshot.docs.map((d: any) => {
        const data: any = d.data();
        return {
          id: d.id,
          bookingRef: String(data.bookingRef ?? ""),
          stripeSessionId: String(data.stripeSessionId ?? ""),
          createdAt: data.createdAt ?? null,
          archivedAt: data.archivedAt ?? null,
          bookedOnRome: "",
          customer: {
            name: String(data.customer?.name ?? ""),
            email: String(data.customer?.email ?? ""),
            phone: String(data.customer?.phone ?? ""),
          },
          dropOff: {
            date: String(data.dropOff?.date ?? ""),
            time: String(data.dropOff?.time ?? ""),
            datetime: data.dropOff?.datetime ?? null,
          },
          pickUp: {
            date: String(data.pickUp?.date ?? ""),
            time: String(data.pickUp?.time ?? ""),
            datetime: data.pickUp?.datetime ?? null,
          },
          billableDays: Number(data.billableDays ?? 0),
          bags: {
            small: Number(data.bags?.small ?? 0),
            medium: Number(data.bags?.medium ?? 0),
            large: Number(data.bags?.large ?? 0),
          },
          totalPaid: Number(data.totalPaid ?? 0),
          currency: String(data.currency ?? "EUR"),
          status: data.status,
          notes: data.notes ?? data.dropOff?.notes ?? "",
          walletIssued: Boolean(data.walletIssued ?? false),
          // Helper for breakdown calculation
          _isArchive: snapshot.query._query?.path?.segments?.includes('bookings_archive')
        };
      });

      setActiveBookings(mapDocs(snapActive));
      setArchivedBookings(mapDocs(snapArchive));
    } catch (err) {
      console.error("Error fetching report data:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAllData();
  }, []);

  const stats = useMemo(() => {
    const filterFn = (b: Booking) => {
      const bDate = b.dropOff.date;
      if (mode === 'day') return bDate === selectedDate;
      if (mode === 'month') return bDate.startsWith(selectedDate);
      if (mode === 'year') return bDate.startsWith(selectedDate.substring(0, 4));
      return false;
    };

    const activeFiltered = activeBookings.filter(filterFn);
    const archivedFiltered = archivedBookings.filter(filterFn);
    const combined = [...activeFiltered, ...archivedFiltered];

    const totalBookings = combined.length;
    const revenue = combined.reduce((acc, b) => b.status !== 'cancelled' ? acc + b.totalPaid : acc, 0);

    const activeRevenue = activeFiltered.reduce((acc, b) => b.status !== 'cancelled' ? acc + b.totalPaid : acc, 0);
    const archivedRevenue = archivedFiltered.reduce((acc, b) => b.status !== 'cancelled' ? acc + b.totalPaid : acc, 0);

    const byStatus = {
      paid: combined.filter(b => b.status === 'paid').length,
      checked_in: combined.filter(b => b.status === 'checked_in').length,
      picked_up: combined.filter(b => b.status === 'picked_up').length,
      cancelled: combined.filter(b => b.status === 'cancelled').length,
    };

    return { 
      totalBookings, 
      revenue, 
      byStatus,
      breakdown: {
        active: { count: activeFiltered.length, rev: activeRevenue },
        archived: { count: archivedFiltered.length, rev: archivedRevenue }
      }
    };
  }, [activeBookings, archivedBookings, mode, selectedDate]);

  const handleArchiveAll = async () => {
    if (!window.confirm("Archive all checked-out bookings older than 7 days?")) return;
    setArchiving(true);
    setArchiveStatus({message: '', type: null});
    try {
      const response = await fetch('/api/archive/picked-up', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ days: 7 })
      });
      const data = await response.json();
      if (response.ok) {
        setArchiveStatus({message: `Success! Archived ${data.count} bookings.`, type: 'success'});
        fetchAllData();
      } else {
        setArchiveStatus({message: data.error || 'Archive failed.', type: 'error'});
      }
    } catch (err) {
      setArchiveStatus({message: 'Network error.', type: 'error'});
    } finally {
      setArchiving(false);
    }
  };

  const handleLogout = () => signOut(auth);

  return (
    <div className="min-h-screen bg-slate-50 pb-12 overflow-x-hidden">
      <header className="bg-white border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Link to="/"><img src={logoUrl} alt="Logo" className="h-8 w-auto" /></Link>
            <h1 className="font-bold text-lg text-slate-900 hidden sm:block">Admin Reports</h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden md:flex items-center gap-4 mr-4 border-r pr-4 border-slate-200">
               <Link to="/" className="text-sm font-bold text-slate-500 hover:text-blue-600 transition-colors">Bookings</Link>
               <Link to="/reports" className="text-sm font-bold text-blue-600">Reports</Link>
            </div>
            <button onClick={handleLogout} className="text-sm font-semibold text-slate-600 hover:text-red-600 transition-colors px-3 py-1.5 hover:bg-red-50 rounded-lg">Sign Out</button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 mt-6">
        <div className="mb-8">
            <h2 className="text-2xl font-bold text-slate-900">Performance Stats</h2>
            <p className="text-slate-500">Analyze combined revenue from active and archived bookings</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
           <div className="flex bg-white p-1.5 rounded-2xl border border-slate-200 shadow-sm w-fit">
              {(['day', 'month', 'year'] as const).map(m => (
                <button
                  key={m}
                  onClick={() => {
                    setMode(m);
                    if (m === 'year') setSelectedDate(new Date().getFullYear().toString());
                    else if (m === 'month') setSelectedDate(new Date().toISOString().substring(0, 7));
                    else setSelectedDate(new Date().toISOString().substring(0, 10));
                  }}
                  className={`px-6 py-2 text-sm font-bold rounded-xl transition-all capitalize ${mode === m ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'text-slate-500 hover:text-slate-900'}`}
                >
                  {m}
                </button>
              ))}
           </div>
           <div className="flex items-center gap-3">
              <input 
                type={mode === 'day' ? 'date' : mode === 'month' ? 'month' : 'number'}
                className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 font-bold outline-none focus:ring-2 focus:ring-blue-500 shadow-sm"
                value={selectedDate}
                min={mode === 'year' ? 2024 : undefined}
                max={mode === 'year' ? 2030 : undefined}
                onChange={(e) => setSelectedDate(e.target.value)}
              />
              <span className="text-slate-400 text-xs font-bold uppercase tracking-widest">Selected Period</span>
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
           <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Total Revenue</p>
              <p className="text-4xl font-black text-emerald-600">{stats.revenue.toLocaleString()} EUR</p>
              <div className="mt-3 space-y-1">
                 <p className="text-[10px] text-slate-500 flex justify-between"><span>Active:</span> <span className="font-bold">{stats.breakdown.active.rev} EUR</span></p>
                 <p className="text-[10px] text-slate-500 flex justify-between"><span>Archived:</span> <span className="font-bold">{stats.breakdown.archived.rev} EUR</span></p>
              </div>
           </div>
           <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Total Bookings</p>
              <p className="text-4xl font-black text-slate-900">{stats.totalBookings}</p>
              <div className="mt-3 space-y-1">
                 <p className="text-[10px] text-slate-500 flex justify-between"><span>Active:</span> <span className="font-bold">{stats.breakdown.active.count}</span></p>
                 <p className="text-[10px] text-slate-500 flex justify-between"><span>Archived:</span> <span className="font-bold">{stats.breakdown.archived.count}</span></p>
              </div>
           </div>
           <div className="bg-slate-900 p-8 rounded-3xl text-white shadow-xl shadow-slate-200">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Avg. Per Booking</p>
              <p className="text-4xl font-black">{stats.totalBookings > 0 ? (stats.revenue / stats.totalBookings).toFixed(2) : '0'} <span className="text-lg opacity-50">EUR</span></p>
              <p className="text-xs text-slate-500 mt-2">Combined lifecycle average</p>
           </div>
        </div>

        <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden mb-12">
           <div className="p-6 border-b border-slate-50">
              <h3 className="font-bold text-slate-900">Status Distribution (Combined)</h3>
           </div>
           <div className="grid grid-cols-2 md:grid-cols-4 divide-x divide-slate-50">
              <div className="p-8 text-center">
                 <p className="text-2xl font-black text-emerald-600">{stats.byStatus.paid}</p>
                 <p className="text-[10px] font-bold text-slate-400 uppercase">Paid</p>
              </div>
              <div className="p-8 text-center">
                 <p className="text-2xl font-black text-blue-600">{stats.byStatus.checked_in}</p>
                 <p className="text-[10px] font-bold text-slate-400 uppercase">In Storage</p>
              </div>
              <div className="p-8 text-center">
                 <p className="text-2xl font-black text-slate-800">{stats.byStatus.picked_up}</p>
                 <p className="text-[10px] font-bold text-slate-400 uppercase">Picked Up</p>
              </div>
              <div className="p-8 text-center">
                 <p className="text-2xl font-black text-red-500">{stats.byStatus.cancelled}</p>
                 <p className="text-[10px] font-bold text-slate-400 uppercase">Cancelled</p>
              </div>
           </div>
        </div>

        <div className="bg-orange-50 border border-orange-100 rounded-3xl p-8">
           <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
              <div className="max-w-lg">
                 <h3 className="text-orange-900 font-bold text-lg mb-1">Database Maintenance</h3>
                 <p className="text-orange-700 text-sm">Use this tool to archive legacy picked-up data that wasn't automatically moved to the archive collection.</p>
              </div>
              <div>
                 <button 
                  onClick={handleArchiveAll}
                  disabled={archiving}
                  className="px-8 py-4 bg-orange-600 text-white rounded-2xl font-bold hover:bg-orange-700 transition-all disabled:opacity-50 shadow-lg shadow-orange-200 whitespace-nowrap"
                 >
                    {archiving ? 'Archiving...' : 'Run Catch-up Archive'}
                 </button>
              </div>
           </div>
           {archiveStatus.type && (
             <div className={`mt-4 p-4 rounded-xl text-sm font-bold ${archiveStatus.type === 'success' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                {archiveStatus.message}
             </div>
           )}
        </div>
      </main>
    </div>
  );
};

