import React, { useState, useEffect, useRef } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { Html5Qrcode } from 'html5-qrcode';
import { auth } from '../firebase';
import StatusBadge from '../components/StatusBadge';

interface BookingSummary {
  id: string;
  bookingRef: string;
  customer: {
    name: string;
    email: string;
    phone: string;
  };
  bags: {
    small: number;
    medium: number;
    large: number;
  };
  dropOff: {
    date: string;
    time: string;
  };
  status: any;
}

const ScanPage: React.FC = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const initialRef = searchParams.get('ref') || searchParams.get('token');
  const [bookingRef, setBookingRef] = useState<string | null>(initialRef);
  const [manualInput, setManualInput] = useState('');
  const [booking, setBooking] = useState<BookingSummary | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [cameraPermissionError, setCameraPermissionError] = useState(false);
  const html5QrCodeRef = useRef<Html5Qrcode | null>(null);

  // Auto-start camera on mount
  useEffect(() => {
    // Lock body scroll for mobile app feel
    document.body.style.overflow = 'hidden';

    if (!bookingRef) {
      startCamera();
    } else {
      lookupBooking(bookingRef);
    }

    return () => {
      stopCamera();
      document.body.style.overflow = 'auto';
    };
  }, []);

  const extractBookingRef = (input: string): string => {
    let cleanInput = input.trim();
    if (cleanInput.includes('ref=')) {
      try {
        const normalized = cleanInput.replace('/#/', '/');
        const url = new URL(normalized);
        const param = url.searchParams.get('ref');
        if (param) return param.toUpperCase();
      } catch (e) {
        const parts = cleanInput.split('ref=');
        if (parts.length > 1) return parts[1].split('&')[0].toUpperCase();
      }
    }
    return cleanInput.toUpperCase();
  };

  const validateAndProcessInput = (rawInput: string) => {
    setError(null);
    const extracted = extractBookingRef(rawInput);
    if (extracted.length < 4) {
      setError("Reference too short.");
      return;
    }
    setBookingRef(extracted);
    lookupBooking(extracted);
  };

  const lookupBooking = async (ref: string) => {
    setLoading(true);
    setError(null);
    setSuccessMessage(null);
    try {
      const response = await fetch('/api/booking/lookup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ bookingRef: ref }),
      });
      const data = await response.json();
      if (response.ok) {
        setBooking(data.booking);
        stopCamera();
      } else {
        setError(data.error || 'Booking not found.');
        setBooking(null);
      }
    } catch (err) {
      setError('Connection error.');
    } finally {
      setLoading(false);
    }
  };

  const startCamera = async () => {
    setError(null);
    setCameraPermissionError(false);
    const html5QrCode = new Html5Qrcode("qr-reader");
    html5QrCodeRef.current = html5QrCode;
    try {
      await html5QrCode.start(
        { facingMode: "environment" },
        { 
          fps: 15, 
          qrbox: { width: 280, height: 280 },
          aspectRatio: 1.0
        },
        (decodedText) => {
          validateAndProcessInput(decodedText);
        },
        () => {}
      );
      setIsCameraActive(true);
    } catch (err) {
      console.error("Camera error:", err);
      setCameraPermissionError(true);
      setIsCameraActive(false);
    }
  };

  const stopCamera = async () => {
    if (html5QrCodeRef.current && html5QrCodeRef.current.isScanning) {
      await html5QrCodeRef.current.stop();
      setIsCameraActive(false);
    }
  };

  const triggerVibrate = () => {
    if ('vibrate' in navigator) {
      navigator.vibrate([200, 100, 200]);
    }
  };

  const handleAction = async (action: 'checkin' | 'pickup') => {
    if (!bookingRef || !booking) return;
    setLoading(true);
    setError(null);
    try {
      const endpoint = action === 'checkin' ? '/api/booking/checkin' : '/api/booking/pickup';
      const response = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ bookingRef, adminEmail: auth.currentUser?.email }),
      });
      if (response.ok) {
        triggerVibrate();
        setSuccessMessage(action === 'checkin' ? 'Checked in successfully ✅' : 'Picked up successfully ✅');
        setTimeout(() => navigate('/'), 2000);
      } else {
        const data = await response.json();
        setError(data.error || 'Action failed.');
      }
    } catch (err) {
      setError('Connection error.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black flex flex-col overflow-hidden">
      {/* App Header */}
      <div className="flex-none bg-slate-900 px-6 py-6 flex items-center justify-between text-white border-b border-slate-800">
        <div className="flex items-center gap-3">
          <button onClick={() => navigate('/')} className="p-2 bg-slate-800 rounded-full hover:bg-slate-700 active:scale-90 transition-all">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
          </button>
          <div>
            <h1 className="text-lg font-black tracking-tight leading-none">Scanner</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Staff Terminal</p>
          </div>
        </div>
        {!booking && !successMessage && (
           <button 
            onClick={() => { setManualInput(''); setBooking(null); setBookingRef(null); startCamera(); }} 
            className="text-xs font-bold text-blue-400 hover:text-blue-300"
          >
             Reset
           </button>
        )}
      </div>

      <div className="flex-1 relative bg-slate-950 flex flex-col justify-center items-center">
        {successMessage ? (
          <div className="w-full max-w-sm px-8 text-center animate-in zoom-in duration-300">
            <div className="w-24 h-24 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-8 border border-emerald-500/30">
              <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
            </div>
            <h2 className="text-3xl font-black text-white mb-4">Success!</h2>
            <p className="text-emerald-400 font-bold text-lg">{successMessage}</p>
            <p className="text-slate-500 text-sm mt-8 animate-pulse">Returning to dashboard...</p>
          </div>
        ) : booking ? (
          <div className="w-full max-w-lg px-6 animate-in slide-in-from-bottom duration-300">
            <div className="bg-white rounded-[2rem] shadow-2xl overflow-hidden border border-slate-200">
               <div className="p-8 space-y-8">
                  <div className="flex justify-between items-start">
                    <div>
                      <p className="text-[10px] font-black uppercase tracking-[0.2em] text-blue-600 mb-1">Booking Confirmed</p>
                      <h2 className="text-4xl font-black text-slate-900">#{booking.bookingRef}</h2>
                    </div>
                    <StatusBadge status={booking.status} />
                  </div>

                  <div className="space-y-4 bg-slate-50 p-6 rounded-3xl border border-slate-100">
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Customer</p>
                      <p className="font-black text-slate-900 text-lg">{booking.customer.name}</p>
                    </div>
                    <div className="flex justify-between border-t border-slate-200 pt-4">
                      <div>
                        <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Schedule</p>
                        <p className="font-bold text-slate-900 text-sm">{booking.dropOff.date}</p>
                        <p className="text-xs text-slate-500">{booking.dropOff.time}</p>
                      </div>
                      <div className="text-right">
                        <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Bags</p>
                        <p className="font-black text-slate-900 text-lg">{booking.bags.small + booking.bags.medium + booking.bags.large}</p>
                      </div>
                    </div>
                  </div>

                  <div className="space-y-4 pt-2">
                    {booking.status === 'paid' && (
                      <button
                        onClick={() => handleAction('checkin')}
                        disabled={loading}
                        className="w-full h-16 bg-blue-600 text-white rounded-2xl font-black text-xl hover:bg-blue-700 shadow-xl shadow-blue-500/20 transition-all active:scale-95 disabled:opacity-50"
                      >
                        {loading ? '...' : 'Confirm Check-In'}
                      </button>
                    )}

                    {booking.status === 'checked_in' && (
                      <button
                        onClick={() => handleAction('pickup')}
                        disabled={loading}
                        className="w-full h-16 bg-emerald-600 text-white rounded-2xl font-black text-xl hover:bg-emerald-700 shadow-xl shadow-emerald-500/20 transition-all active:scale-95 disabled:opacity-50"
                      >
                        {loading ? '...' : 'Mark Picked Up'}
                      </button>
                    )}

                    {(booking.status === 'picked_up' || booking.status === 'cancelled') && (
                      <div className="p-6 bg-slate-100 rounded-3xl text-center text-slate-500 font-black italic border border-slate-200">
                        Booking is {booking.status.replace('_', ' ')}
                      </div>
                    )}
                  </div>
               </div>
            </div>
            <button 
              onClick={() => { setBooking(null); setBookingRef(null); startCamera(); }}
              className="w-full mt-6 text-white/50 font-bold text-sm uppercase tracking-[0.2em] hover:text-white transition-colors"
            >
              Scan Another
            </button>
          </div>
        ) : (
          <div className="w-full h-full flex flex-col">
            {/* Scanner Viewport */}
            <div className="flex-1 relative flex items-center justify-center bg-black">
               <div id="qr-reader" className="w-full h-full"></div>

               {/* Scanner Overlay Frame */}
               {isCameraActive && (
                 <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                    <div className="w-[280px] h-[280px] border-2 border-white/30 rounded-[3rem] shadow-[0_0_0_1000px_rgba(0,0,0,0.6)] relative overflow-hidden">
                       <div className="absolute inset-0 border-[3px] border-blue-500/80 rounded-[3rem] animate-pulse"></div>
                       {/* Scanning line animation */}
                       <div className="absolute top-0 left-0 right-0 h-1 bg-blue-500 shadow-[0_0_15px_rgba(59,130,246,1)] animate-[scan_3s_ease-in-out_infinite]"></div>
                    </div>
                    <style>{`
                      @keyframes scan {
                        0%, 100% { top: 10%; }
                        50% { top: 90%; }
                      }
                    `}</style>
                 </div>
               )}

               {cameraPermissionError && (
                 <div className="absolute inset-0 bg-slate-900 flex flex-col items-center justify-center p-8 text-center z-20">
                    <div className="w-20 h-20 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-6 border border-red-500/30">
                       <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                    </div>
                    <h3 className="text-white text-xl font-black mb-2">Camera Blocked</h3>
                    <p className="text-slate-400 text-sm mb-8">Access is required to scan QR codes. Please update your browser permissions.</p>
                    <button 
                      onClick={startCamera} 
                      className="px-8 py-4 bg-white text-slate-900 rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl active:scale-95 transition-all"
                    >
                      Allow Camera
                    </button>
                 </div>
               )}
            </div>

            {/* Manual Entry Drawer */}
            <div className="flex-none bg-slate-900 p-8 pt-4 pb-12 rounded-t-[3rem] shadow-[0_-20px_50px_rgba(0,0,0,0.5)] border-t border-slate-800">
               <div className="w-12 h-1 bg-slate-700 rounded-full mx-auto mb-6"></div>
               <div className="relative mb-6">
                 <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-slate-800"></div></div>
                 <div className="relative flex justify-center text-[10px]"><span className="px-3 bg-slate-900 text-slate-500 font-black uppercase tracking-[0.3em]">Manual Lookup</span></div>
               </div>

               <form onSubmit={(e) => { e.preventDefault(); validateAndProcessInput(manualInput); }} className="space-y-4">
                  <input 
                    type="text" 
                    autoFocus
                    value={manualInput}
                    onChange={(e) => setManualInput(e.target.value)}
                    placeholder="ENTER REFERENCE"
                    className="w-full h-16 bg-slate-800 border-2 border-slate-700 rounded-2xl text-white text-center text-xl font-black tracking-[0.2em] outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition-all placeholder:text-slate-600"
                  />
                  <button type="submit" className="w-full h-12 bg-slate-100 text-slate-900 rounded-xl text-sm font-black uppercase tracking-widest hover:bg-white active:scale-98 transition-all">
                    Search Booking
                  </button>
               </form>

               {error && (
                 <div className="mt-4 p-4 bg-red-500/10 text-red-500 rounded-2xl text-[10px] font-black uppercase tracking-widest text-center animate-in fade-in">
                    Error: {error}
                 </div>
               )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ScanPage;

import React, { useState, useEffect, useMemo } from 'react';
import { collection, query, orderBy, onSnapshot } from 'firebase/firestore';
import { signOut } from 'firebase/auth';
import { useNavigate, Link } from 'react-router-dom';
import { auth, db } from '../firebase';
import { Booking, BookingStatus } from '../types';
import StatusBadge from '../components/StatusBadge';
import BookingDetailModal from '../components/BookingDetailModal';

type DateFilter = 'all' | 'today' | 'upcoming' | 'past';
type ViewMode = 'active' | 'archived';

const DashboardPage: React.FC = () => {
  const navigate = useNavigate();
  const [viewMode, setViewMode] = useState<ViewMode>('active');
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [search, setSearch] = useState('');
  const [dateFilter, setDateFilter] = useState<DateFilter>('all');
  const [statusFilter, setStatusFilter] = useState<BookingStatus | 'all'>('all');
  const [selectedBookingId, setSelectedBookingId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [queryError, setQueryError] = useState<string | null>(null);

  const logoUrl = "https://cdn.shopify.com/s/files/1/0753/8144/0861/files/cropped-Untitled-design-2025-09-11T094640.576_1.png?v=1765462614&width=160&format=webp";

  const selectedBooking = useMemo(() => 
    bookings.find(b => b.id === selectedBookingId) || null,
    [bookings, selectedBookingId]
  );

  useEffect(() => {
    setLoading(true);
    setQueryError(null);
    const collectionName = viewMode === 'active' ? "bookings" : "bookings_archive";
    const sortField = viewMode === 'active' ? "createdAt" : "archivedAt";

    try {
      const q = query(collection(db, collectionName), orderBy(sortField, "desc"));

      const unsubscribe = onSnapshot(
        q,
        (snapshot) => {
          const docs: Booking[] = snapshot.docs.map((d) => {
            const data: any = d.data();
            return {
              id: d.id,
              bookingRef: String(data.bookingRef ?? ""),
              stripeSessionId: String(data.stripeSessionId ?? ""),
              createdAt: data.createdAt ?? null,
              archivedAt: data.archivedAt ?? null,
              bookedOnRome: "",
              customer: {
                name: String(data.customer?.name ?? ""),
                email: String(data.customer?.email ?? ""),
                phone: String(data.customer?.phone ?? ""),
              },
              dropOff: {
                date: String(data.dropOff?.date ?? ""),
                time: String(data.dropOff?.time ?? ""),
                datetime: data.dropOff?.datetime ?? null,
              },
              pickUp: {
                date: String(data.pickUp?.date ?? ""),
                time: String(data.pickUp?.time ?? ""),
                datetime: data.pickUp?.datetime ?? null,
              },
              billableDays: Number(data.billableDays ?? 0),
              bags: {
                small: Number(data.bags?.small ?? 0),
                medium: Number(data.bags?.medium ?? 0),
                large: Number(data.bags?.large ?? 0),
              },
              totalPaid: Number(data.totalPaid ?? 0),
              currency: String(data.currency ?? "EUR"),
              status: (data.status ?? "paid") as any,
              notes: String(data.notes ?? data.dropOff?.notes ?? ""),
              walletIssued: Boolean(data.walletIssued ?? false),
            };
          });

          setBookings(docs);
          setLoading(false);
          setQueryError(null);
        },
        (err) => {
          console.error(`Firestore ${collectionName} snapshot error:`, err);
          setQueryError(`${err.name}: ${err.message}`);
          setBookings([]);
          setLoading(false);
        }
      );

      return () => unsubscribe();
    } catch (err: any) {
      setQueryError(err.message);
      setLoading(false);
      return () => {};
    }
  }, [viewMode]);

  const filteredBookings = useMemo(() => {
    const now = new Date();
    const todayStr = now.toISOString().split('T')[0];

    return bookings.filter(b => {
      const s = search.toLowerCase();
      const matchesSearch = !search || 
        b.bookingRef.toLowerCase().includes(s) || 
        b.customer.email.toLowerCase().includes(s) || 
        b.customer.phone.toLowerCase().includes(s) ||
        b.customer.name.toLowerCase().includes(s);

      const matchesStatus = statusFilter === 'all' || b.status === statusFilter;

      const bookingDate = b.dropOff.date;
      let matchesDate = true;
      if (dateFilter === 'today') matchesDate = bookingDate === todayStr;
      else if (dateFilter === 'upcoming') matchesDate = bookingDate > todayStr;
      else if (dateFilter === 'past') matchesDate = bookingDate < todayStr;

      return matchesSearch && matchesStatus && matchesDate;
    });
  }, [bookings, search, dateFilter, statusFilter]);

  const handleLogout = () => signOut(auth);

  return (
    <div className="min-h-screen bg-slate-50 pb-20 sm:pb-12 overflow-x-hidden">
      <header className="bg-white border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <img src={logoUrl} alt="Logo" className="h-8 w-auto" />
            <h1 className="font-black text-lg text-slate-900 hidden sm:block tracking-tight">Admin Terminal</h1>
          </div>
          <div className="flex items-center gap-2 sm:gap-4">
            <div className="hidden md:flex items-center gap-4 mr-4 border-r pr-4 border-slate-200">
               <Link to="/" className="text-sm font-bold text-blue-600">Bookings</Link>
               <Link to="/reports" className="text-sm font-bold text-slate-500 hover:text-blue-600 transition-colors">Reports</Link>
            </div>
            <button 
              onClick={() => navigate('/scan')}
              className="flex items-center gap-2 px-4 py-2.5 bg-blue-600 text-white rounded-xl text-sm font-black hover:bg-blue-700 transition-all shadow-lg shadow-blue-500/20 active:scale-95"
            >
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" /></svg>
              <span className="hidden sm:inline">Scan QR</span>
            </button>
            <button 
              onClick={handleLogout}
              className="text-xs font-bold text-slate-400 hover:text-red-600 transition-colors px-3 py-2 hover:bg-red-50 rounded-lg"
            >
              Log Out
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 mt-6">
        {queryError && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-2xl text-red-700 animate-in fade-in slide-in-from-top-4 duration-300 shadow-sm">
            <div className="flex items-center gap-2 mb-1">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
              <h3 className="font-bold text-xs uppercase tracking-widest">Service Alert</h3>
            </div>
            <p className="text-[10px] font-mono leading-relaxed opacity-80">{queryError}</p>
          </div>
        )}

        {/* Action Header Block */}
        <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-6 mb-8">
          <div className="space-y-1">
            <div className="flex items-center gap-3">
              <h2 className="text-3xl font-black text-slate-900 tracking-tight">Records</h2>
              <div className="flex bg-slate-100 p-1 rounded-xl">
                 <button 
                  onClick={() => setViewMode('active')}
                  className={`px-4 py-1.5 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${viewMode === 'active' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  Active
                </button>
                <button 
                  onClick={() => setViewMode('archived')}
                  className={`px-4 py-1.5 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${viewMode === 'archived' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  Archive
                </button>
              </div>
            </div>
            <p className="text-slate-500 font-medium text-sm">Reviewing {viewMode} luggage storage data</p>
          </div>

          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative group">
              <input
                type="text"
                placeholder="Name, Ref, Phone..."
                className="pl-12 pr-6 py-3.5 bg-white border-2 border-slate-100 rounded-2xl outline-none focus:ring-4 focus:ring-blue-50 focus:border-blue-500 w-full sm:w-80 transition-all font-medium text-slate-700 placeholder:text-slate-300"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
              <svg className="w-6 h-6 absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-blue-500 transition-colors" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </div>
          </div>
        </div>

        {/* Flexible Filter Tabs (Wrapped for Mobile) */}
        <div className="space-y-3 mb-8">
          <div className="flex flex-wrap gap-2">
            {(['all', 'today', 'upcoming', 'past'] as const).map((f) => (
              <button
                key={f}
                onClick={() => setDateFilter(f)}
                className={`px-5 py-2.5 text-xs font-bold rounded-xl border-2 transition-all capitalize ${dateFilter === f ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-500/20' : 'bg-white border-slate-100 text-slate-500 hover:border-slate-300'}`}
              >
                {f}
              </button>
            ))}
          </div>

          <div className="flex flex-wrap gap-2">
            {(['all', 'paid', 'checked_in', 'picked_up', 'cancelled'] as const).map((s) => (
              <button
                key={s}
                onClick={() => setStatusFilter(s)}
                className={`px-5 py-2.5 text-xs font-bold rounded-xl border-2 transition-all capitalize ${statusFilter === s ? 'bg-slate-900 border-slate-900 text-white shadow-lg shadow-slate-900/20' : 'bg-white border-slate-100 text-slate-500 hover:border-slate-300'}`}
              >
                {s.replace('_', ' ')}
              </button>
            ))}
          </div>
        </div>

        {/* Main List Container */}
        <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden mb-12">
          {loading ? (
            <div className="p-32 text-center">
               <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
               <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Querying Records...</p>
            </div>
          ) : filteredBookings.length === 0 ? (
            <div className="p-32 text-center">
              <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-200">
                 <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              </div>
              <p className="text-slate-500 font-bold mb-4">No results for this selection</p>
              <button onClick={() => { setSearch(''); setDateFilter('all'); setStatusFilter('all'); }} className="text-blue-600 font-black text-xs uppercase tracking-widest hover:underline">Reset All Filters</button>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-slate-50/50 text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] border-b border-slate-100">
                    <th className="px-6 py-5">Reference</th>
                    <th className="px-6 py-5">Guest</th>
                    <th className="hidden md:table-cell px-6 py-5">Drop-off</th>
                    <th className="hidden sm:table-cell px-6 py-5 text-center">Bags</th>
                    <th className="hidden md:table-cell px-6 py-5">Status</th>
                    <th className="px-6 py-5 text-right">Total</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredBookings.map((booking) => (
                    <tr 
                      key={booking.id} 
                      className="hover:bg-slate-50/80 transition-colors cursor-pointer active:bg-slate-100"
                      onClick={() => setSelectedBookingId(booking.id)}
                    >
                      <td className="px-6 py-5 align-top">
                        <span className="font-mono font-black text-slate-900 block text-sm">#{booking.bookingRef}</span>
                        {/* Mobile Status + Time */}
                        <div className="md:hidden mt-2 flex flex-col gap-2 items-start">
                          <StatusBadge status={booking.status} />
                          <p className="text-[10px] text-slate-500 font-bold">
                            {booking.dropOff.date} • {booking.dropOff.time}
                          </p>
                        </div>
                      </td>
                      <td className="px-6 py-5 align-top">
                        <p className="font-black text-slate-900 text-sm truncate max-w-[120px] sm:max-w-none">{booking.customer.name}</p>
                        <p className="text-[10px] text-slate-400 font-bold hidden sm:block mt-0.5">{booking.customer.email}</p>
                      </td>
                      <td className="hidden md:table-cell px-6 py-5 align-top">
                        <p className="text-sm font-black text-slate-900">{booking.dropOff.date}</p>
                        <p className="text-[10px] text-slate-400 font-bold mt-0.5 uppercase">{booking.dropOff.time}</p>
                      </td>
                      <td className="hidden sm:table-cell px-6 py-5 align-top text-center">
                        <span className="text-xs px-2.5 py-1 bg-slate-100 rounded-lg font-black text-slate-600">
                          {booking.bags.small + booking.bags.medium + booking.bags.large}
                        </span>
                      </td>
                      <td className="hidden md:table-cell px-6 py-5 align-top">
                        <StatusBadge status={booking.status} />
                      </td>
                      <td className="px-6 py-5 font-black text-slate-900 text-sm align-top text-right">
                        {booking.totalPaid} <span className="text-[10px] text-slate-400 uppercase">{booking.currency}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </main>

      {/* Floating Scan Button (Mobile Only) */}
      <div className="sm:hidden fixed bottom-6 left-1/2 -translate-x-1/2 z-30">
         <button 
           onClick={() => navigate('/scan')}
           className="px-8 py-5 bg-blue-600 text-white rounded-full font-black text-lg shadow-2xl shadow-blue-500/40 active:scale-95 transition-all flex items-center gap-3 border-4 border-white"
         >
           <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" /></svg>
           Scan QR
         </button>
      </div>

      {selectedBooking && (
        <BookingDetailModal
          booking={selectedBooking}
          onClose={() => setSelectedBookingId(null)}
          onUpdate={() => {}}
        />
      )}
    </div>
  );
};

export default DashboardPage;

import React, { useState } from 'react';
import { Booking, BookingStatus } from '../types';
import { doc, updateDoc, serverTimestamp } from 'firebase/firestore';
import { db, auth } from '../firebase';
import StatusBadge from './StatusBadge';

interface BookingDetailModalProps {
  booking: Booking;
  onClose: () => void;
  onUpdate: () => void;
}

const BookingDetailModal: React.FC<BookingDetailModalProps> = ({ booking, onClose, onUpdate }) => {
  const [notes, setNotes] = useState(booking.notes || '');
  const [updating, setUpdating] = useState(false);

  const updateStatus = async (newStatus: BookingStatus) => {
    setUpdating(true);
    try {
      if (newStatus === 'picked_up') {
        const response = await fetch('/api/archive/pickup', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ 
            bookingRef: booking.bookingRef,
            adminEmail: auth.currentUser?.email 
          }),
        });

        if (!response.ok) {
          const data = await response.json();
          throw new Error(data.error || 'Failed to archive booking');
        }

        onClose();
        return;
      }

      const bookingRef = doc(db, 'bookings', booking.id);
      const updateData: any = { status: newStatus, updatedAt: serverTimestamp() };

      if (newStatus === 'checked_in') updateData.checkedInAt = serverTimestamp();

      await updateDoc(bookingRef, updateData);
      onUpdate();
    } catch (err: any) {
      console.error(err);
      alert(err.message || 'Failed to update status');
    } finally {
      setUpdating(false);
    }
  };

  const saveNotes = async () => {
    setUpdating(true);
    try {
      const bookingRef = doc(db, 'bookings', booking.id);
      await updateDoc(bookingRef, { 'dropOff.notes': notes });
      onUpdate();
    } catch (err) {
      alert('Failed to save notes. Note: Archived bookings are read-only.');
    } finally {
      setUpdating(false);
    }
  };

  const isArchived = !!booking.archivedAt;

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/70 backdrop-blur-md overflow-hidden">
      {/* Background overlay */}
      <div className="absolute inset-0" onClick={onClose}></div>

      <div className="relative bg-white rounded-t-[2.5rem] sm:rounded-[2rem] shadow-2xl w-full max-w-2xl h-[90vh] sm:h-auto sm:max-h-[85vh] flex flex-col animate-in slide-in-from-bottom duration-300">

        {/* Header - Fixed */}
        <div className="flex-none px-6 py-5 flex items-center justify-between border-b border-slate-50">
          <div>
            <div className="flex items-center gap-2">
              <h2 className="text-xl font-black text-slate-900">#{booking.bookingRef}</h2>
              {isArchived && <span className="bg-slate-900 text-white text-[9px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest">Archive</span>}
            </div>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">Guest Information</p>
          </div>
          <button onClick={onClose} className="p-2.5 bg-slate-100 rounded-full text-slate-400 hover:text-slate-900 transition-colors active:scale-90">
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto p-6 space-y-8 pb-40 sm:pb-8 custom-scrollbar">

          {/* Profile Header */}
          <div className="bg-slate-900 rounded-3xl p-6 text-white shadow-xl shadow-slate-200">
             <div className="flex justify-between items-start mb-4">
                <StatusBadge status={booking.status} />
                <p className="text-[10px] font-black opacity-50 uppercase tracking-widest">Deposit Due</p>
             </div>
             <h3 className="text-2xl font-black mb-1">{booking.customer.name}</h3>
             <p className="text-slate-400 text-sm font-medium mb-4">{booking.customer.email}</p>
             <div className="flex items-center gap-2 text-blue-400 font-black text-sm">
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 5a2 2 0 012-2h3.28a1 1 0 01.948.684l1.498 4.493a1 1 0 01-.502 1.21l-2.257 1.13a11.042 11.042 0 005.516 5.516l1.13-2.257a1 1 0 011.21-.502l4.493 1.498a1 1 0 01.684.949V19a2 2 0 01-2 2h-1C9.716 21 3 14.284 3 6V5z" /></svg>
                {booking.customer.phone}
             </div>
          </div>

          {/* Logistics Grid */}
          <div className="grid grid-cols-2 gap-4">
            <div className="p-5 bg-blue-50/50 rounded-3xl border border-blue-100/50">
              <p className="text-[9px] font-black text-blue-400 uppercase tracking-widest mb-2">Drop-off</p>
              <p className="font-black text-slate-900 text-sm">{booking.dropOff.date}</p>
              <p className="text-[10px] text-blue-600 font-bold">{booking.dropOff.time}</p>
            </div>
            <div className="p-5 bg-emerald-50/50 rounded-3xl border border-emerald-100/50">
              <p className="text-[9px] font-black text-emerald-400 uppercase tracking-widest mb-2">Pick-up</p>
              <p className="font-black text-slate-900 text-sm">{booking.pickUp.date}</p>
              <p className="text-[10px] text-emerald-600 font-bold">{booking.pickUp.time}</p>
            </div>
          </div>

          {/* Bag Inventory */}
          <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
             <div className="flex justify-between items-center mb-4">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Luggage Inventory</h4>
                <span className="text-xs font-black text-slate-900">{booking.bags.small + booking.bags.medium + booking.bags.large} Total</span>
             </div>
             <div className="grid grid-cols-3 gap-2">
                <div className="text-center p-3 bg-white rounded-2xl border border-slate-100 shadow-sm">
                   <p className="text-lg font-black text-slate-900">{booking.bags.small}</p>
                   <p className="text-[8px] font-bold text-slate-400 uppercase">Small</p>
                </div>
                <div className="text-center p-3 bg-white rounded-2xl border border-slate-100 shadow-sm">
                   <p className="text-lg font-black text-slate-900">{booking.bags.medium}</p>
                   <p className="text-[8px] font-bold text-slate-400 uppercase">Medium</p>
                </div>
                <div className="text-center p-3 bg-white rounded-2xl border border-slate-100 shadow-sm">
                   <p className="text-lg font-black text-slate-900">{booking.bags.large}</p>
                   <p className="text-[8px] font-bold text-slate-400 uppercase">Large</p>
                </div>
             </div>
          </div>

          {/* Memo Section */}
          {!isArchived && (
            <div className="space-y-3">
              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Internal Memo</h4>
              <div className="relative group">
                <textarea
                  className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-3xl h-28 focus:border-blue-500 focus:bg-white focus:ring-4 focus:ring-blue-50 outline-none transition-all text-sm font-medium placeholder:text-slate-300 resize-none"
                  placeholder="Storage location or notes..."
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                />
                <button 
                  onClick={saveNotes} 
                  disabled={updating}
                  className="absolute bottom-3 right-3 px-4 py-2 bg-slate-900 text-white text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-black active:scale-95 disabled:opacity-30 transition-all shadow-lg"
                >
                  {updating ? '...' : 'Save'}
                </button>
              </div>
            </div>
          )}
        </div>

        {/* STICKY BOTTOM ACTIONS */}
        {!isArchived && (
          <div className="flex-none p-4 sm:p-8 bg-white border-t border-slate-50 shadow-[0_-20px_40px_rgba(0,0,0,0.03)] rounded-t-[2.5rem] sm:rounded-none z-20">
            <div className="flex flex-col sm:flex-row gap-3">
              {/* Highlight primary action based on current status */}
              <button 
                onClick={() => updateStatus('checked_in')}
                disabled={updating || booking.status !== 'paid'}
                className={`flex-1 h-16 sm:h-14 rounded-2xl text-base font-black transition-all active:scale-95 
                  ${booking.status === 'paid' 
                    ? 'bg-blue-600 text-white shadow-xl shadow-blue-500/20' 
                    : 'bg-slate-50 text-slate-300 border border-slate-100 opacity-50 shadow-none pointer-events-none'}`}
              >
                Mark Checked In
              </button>

              <button 
                onClick={() => updateStatus('picked_up')}
                disabled={updating || booking.status !== 'checked_in'}
                className={`flex-1 h-16 sm:h-14 rounded-2xl text-base font-black transition-all active:scale-95
                  ${booking.status === 'checked_in'
                    ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-500/20'
                    : 'bg-slate-50 text-slate-300 border border-slate-100 opacity-50 shadow-none pointer-events-none'}`}
              >
                Mark Picked Up
              </button>

              <button 
                onClick={() => updateStatus('cancelled')}
                disabled={updating || booking.status === 'picked_up' || booking.status === 'cancelled'}
                className="sm:w-32 h-16 sm:h-14 bg-red-50 text-red-600 rounded-2xl text-sm font-black hover:bg-red-100 active:scale-95 disabled:opacity-30 disabled:bg-slate-50 disabled:text-slate-300 transition-all"
              >
                Cancel
              </button>
            </div>
          </div>
        )}

        {/* Mobile Safe Area Spacer */}
        <div className="h-4 sm:hidden bg-white"></div>
      </div>
    </div>
  );
};

export default BookingDetailModal;

import React, { useState, useEffect, useMemo } from 'react';
import { collection, query, orderBy, onSnapshot } from 'firebase/firestore';
import { signOut } from 'firebase/auth';
import { useNavigate, Link } from 'react-router-dom';
import { auth, db } from '../firebase';
import { Booking, BookingStatus } from '../types';
import StatusBadge from '../components/StatusBadge';
import BookingDetailModal from '../components/BookingDetailModal';

type DateFilter = 'all' | 'today' | 'upcoming' | 'past';
type ViewMode = 'active' | 'archived';

const DashboardPage: React.FC = () => {
  const navigate = useNavigate();
  const [viewMode, setViewMode] = useState<ViewMode>('active');
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [search, setSearch] = useState('');
  const [dateFilter, setDateFilter] = useState<DateFilter>('all');
  const [statusFilter, setStatusFilter] = useState<BookingStatus | 'all'>('all');
  const [selectedBookingId, setSelectedBookingId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [queryError, setQueryError] = useState<string | null>(null);

  const logoUrl = "https://cdn.shopify.com/s/files/1/0753/8144/0861/files/cropped-Untitled-design-2025-09-11T094640.576_1.png?v=1765462614&width=160&format=webp";

  const selectedBooking = useMemo(() => 
    bookings.find(b => b.id === selectedBookingId) || null,
    [bookings, selectedBookingId]
  );

  useEffect(() => {
    setLoading(true);
    setQueryError(null);
    const collectionName = viewMode === 'active' ? "bookings" : "bookings_archive";
    const sortField = viewMode === 'active' ? "createdAt" : "archivedAt";

    try {
      const q = query(collection(db, collectionName), orderBy(sortField, "desc"));

      const unsubscribe = onSnapshot(
        q,
        (snapshot) => {
          const docs: Booking[] = snapshot.docs.map((d) => {
            const data: any = d.data();
            return {
              id: d.id,
              bookingRef: String(data.bookingRef ?? ""),
              stripeSessionId: String(data.stripeSessionId ?? ""),
              createdAt: data.createdAt ?? null,
              archivedAt: data.archivedAt ?? null,
              bookedOnRome: "",
              customer: {
                name: String(data.customer?.name ?? ""),
                email: String(data.customer?.email ?? ""),
                phone: String(data.customer?.phone ?? ""),
              },
              dropOff: {
                date: String(data.dropOff?.date ?? ""),
                time: String(data.dropOff?.time ?? ""),
                datetime: data.dropOff?.datetime ?? null,
              },
              pickUp: {
                date: String(data.pickUp?.date ?? ""),
                time: String(data.pickUp?.time ?? ""),
                datetime: data.pickUp?.datetime ?? null,
              },
              billableDays: Number(data.billableDays ?? 0),
              bags: {
                small: Number(data.bags?.small ?? 0),
                medium: Number(data.bags?.medium ?? 0),
                large: Number(data.bags?.large ?? 0),
              },
              totalPaid: Number(data.totalPaid ?? 0),
              currency: String(data.currency ?? "EUR"),
              status: (data.status ?? "paid") as any,
              notes: String(data.notes ?? data.dropOff?.notes ?? ""),
              walletIssued: Boolean(data.walletIssued ?? false),
            };
          });

          setBookings(docs);
          setLoading(false);
          setQueryError(null);
        },
        (err) => {
          console.error(`Firestore ${collectionName} snapshot error:`, err);
          setQueryError(`${err.name}: ${err.message}`);
          setBookings([]);
          setLoading(false);
        }
      );

      return () => unsubscribe();
    } catch (err: any) {
      setQueryError(err.message);
      setLoading(false);
      return () => {};
    }
  }, [viewMode]);

  const filteredBookings = useMemo(() => {
    const now = new Date();
    const todayStr = now.toISOString().split('T')[0];

    return bookings.filter(b => {
      const s = search.toLowerCase();
      const matchesSearch = !search || 
        b.bookingRef.toLowerCase().includes(s) || 
        b.customer.email.toLowerCase().includes(s) || 
        b.customer.phone.toLowerCase().includes(s) ||
        b.customer.name.toLowerCase().includes(s);

      const matchesStatus = statusFilter === 'all' || b.status === statusFilter;

      const bookingDate = b.dropOff.date;
      let matchesDate = true;
      if (dateFilter === 'today') matchesDate = bookingDate === todayStr;
      else if (dateFilter === 'upcoming') matchesDate = bookingDate > todayStr;
      else if (dateFilter === 'past') matchesDate = bookingDate < todayStr;

      return matchesSearch && matchesStatus && matchesDate;
    });
  }, [bookings, search, dateFilter, statusFilter]);

  const handleLogout = () => signOut(auth);

  return (
    <div className="min-h-screen bg-slate-50 pb-32 overflow-x-hidden flex flex-col">
      {/* App Header */}
      <header className="bg-white border-b border-slate-100 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <img src={logoUrl} alt="Logo" className="h-8 w-auto" />
            <h1 className="font-black text-lg text-slate-900 hidden sm:block tracking-tighter uppercase">Terminal</h1>
          </div>
          <div className="flex items-center gap-3">
            <div className="hidden md:flex items-center gap-6 mr-6 border-r pr-6 border-slate-100">
               <Link to="/" className="text-sm font-black text-blue-600 uppercase tracking-widest">Bookings</Link>
               <Link to="/reports" className="text-sm font-black text-slate-300 hover:text-blue-600 transition-colors uppercase tracking-widest">Reports</Link>
            </div>
            <button 
              onClick={handleLogout}
              className="text-[10px] font-black text-slate-400 hover:text-red-500 uppercase tracking-widest px-3 py-2 transition-all"
            >
              Sign Out
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 mt-6 w-full flex-1">
        {queryError && (
          <div className="mb-6 p-4 bg-red-50 border-2 border-red-100 rounded-3xl text-red-600 animate-in fade-in duration-300 flex gap-3 items-center">
            <svg className="w-5 h-5 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
            <p className="text-[10px] font-mono leading-relaxed">{queryError}</p>
          </div>
        )}

        {/* Page Heading & Search */}
        <div className="mb-10 space-y-6">
          <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-4">
            <div className="space-y-1">
              <div className="flex items-center gap-4">
                <h2 className="text-4xl font-black text-slate-900 tracking-tight">Orders</h2>
                <div className="bg-slate-200 p-1 rounded-2xl flex shadow-inner">
                   <button 
                    onClick={() => setViewMode('active')}
                    className={`px-5 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${viewMode === 'active' ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
                  >
                    Active
                  </button>
                  <button 
                    onClick={() => setViewMode('archived')}
                    className={`px-5 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${viewMode === 'archived' ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
                  >
                    Archive
                  </button>
                </div>
              </div>
              <p className="text-slate-400 font-bold text-sm tracking-tight">Real-time luggage management system</p>
            </div>

            <div className="relative group w-full sm:w-auto">
              <input
                type="text"
                placeholder="Search Guest or Ref..."
                className="pl-12 pr-6 py-4 bg-white border-2 border-slate-100 rounded-[1.5rem] outline-none focus:ring-4 focus:ring-blue-50 focus:border-blue-500 w-full sm:w-80 transition-all font-bold text-slate-700 placeholder:text-slate-300 shadow-sm"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
              <svg className="w-6 h-6 absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-blue-500 transition-colors" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </div>
          </div>

          {/* HIERARCHICAL FILTERS */}
          <div className="space-y-4">
            {/* Primary Filter Row */}
            <div className="flex flex-wrap gap-2">
              {(['all', 'today', 'upcoming', 'past'] as const).map((f) => (
                <button
                  key={f}
                  onClick={() => setDateFilter(f)}
                  className={`px-6 py-3 text-xs font-black rounded-2xl border-2 transition-all capitalize shadow-sm ${dateFilter === f ? 'bg-blue-600 border-blue-600 text-white shadow-xl shadow-blue-500/20' : 'bg-white border-slate-100 text-slate-500 hover:border-slate-300'}`}
                >
                  {f}
                </button>
              ))}
            </div>

            {/* Secondary Filter Row */}
            <div className="flex flex-wrap gap-2">
              {(['all', 'paid', 'checked_in', 'picked_up', 'cancelled'] as const).map((s) => (
                <button
                  key={s}
                  onClick={() => setStatusFilter(s)}
                  className={`px-4 py-2 text-[10px] font-black rounded-xl border transition-all capitalize uppercase tracking-widest ${statusFilter === s ? 'bg-slate-900 border-slate-900 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400 hover:text-slate-600 hover:bg-white'}`}
                >
                  {s.replace('_', ' ')}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Data Container */}
        <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden min-h-[400px]">
          {loading ? (
            <div className="flex flex-col items-center justify-center p-32 space-y-4">
               <div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
               <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.3em]">Syncing...</p>
            </div>
          ) : filteredBookings.length === 0 ? (
            <div className="flex flex-col items-center justify-center p-32 text-center">
              <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-8 text-slate-200">
                 <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 8h14M5 8a2 2 0 110-4h14a2 2 0 110 4M5 8v10a2 2 0 002 2h10a2 2 0 002-2V8m-9 4h4" /></svg>
              </div>
              <p className="text-slate-900 font-black text-xl mb-2">No Records Found</p>
              <p className="text-slate-400 text-sm font-medium mb-8">Try adjusting your filters or search terms.</p>
              <button onClick={() => { setSearch(''); setDateFilter('all'); setStatusFilter('all'); }} className="px-8 py-3 bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest rounded-2xl hover:bg-black transition-all">Clear Filters</button>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-slate-50/50 text-slate-400 text-[9px] font-black uppercase tracking-[0.2em] border-b border-slate-50">
                    <th className="px-8 py-6">Ref & Status</th>
                    <th className="px-8 py-6">Guest</th>
                    <th className="hidden lg:table-cell px-8 py-6">Drop-off</th>
                    <th className="hidden sm:table-cell px-8 py-6 text-center">Bags</th>
                    <th className="px-8 py-6 text-right">Revenue</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredBookings.map((booking) => (
                    <tr 
                      key={booking.id} 
                      className="hover:bg-blue-50/30 transition-all cursor-pointer group active:bg-slate-100"
                      onClick={() => setSelectedBookingId(booking.id)}
                    >
                      <td className="px-8 py-6 align-top">
                        <span className="font-mono font-black text-slate-900 block text-base mb-2 group-hover:text-blue-600 transition-colors">#{booking.bookingRef}</span>
                        <div className="flex items-center gap-2">
                           <StatusBadge status={booking.status} />
                           {/* Mobile only date indicator */}
