import React, { useState, useEffect, useRef } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { Html5Qrcode } from 'html5-qrcode';
import { auth } from '../firebase';
import StatusBadge from '../components/StatusBadge';

interface BookingSummary {
  id: string;
  bookingRef: string;
  customer: {
    name: string;
    email: string;
    phone: string;
  };
  bags: {
    small: number;
    medium: number;
    large: number;
  };
  dropOff: {
    date: string;
    time: string;
  };
  status: any;
}

const ScanPage: React.FC = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const initialRef = searchParams.get('ref') || searchParams.get('token');
  const [bookingRef, setBookingRef] = useState<string | null>(initialRef);
  const [manualInput, setManualInput] = useState('');
  const [booking, setBooking] = useState<BookingSummary | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [scanFeedback, setScanFeedback] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [cameraPermissionError, setCameraPermissionError] = useState(false);
  const html5QrCodeRef = useRef<Html5Qrcode | null>(null);

  // Auto-start camera on mount
  useEffect(() => {
    document.body.style.overflow = 'hidden';

    if (!bookingRef) {
      startCamera();
    } else {
      lookupBooking(bookingRef);
    }

    return () => {
      stopCamera();
      document.body.style.overflow = 'auto';
    };
  }, []);

  const triggerVibrate = () => {
    if ('vibrate' in navigator) {
      navigator.vibrate([200, 100, 200]);
    }
  };

  const lookupBooking = async (ref: string) => {
    setLoading(true);
    setError(null);
    setSuccessMessage(null);
    try {
      const response = await fetch('/api/booking/lookup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ bookingRef: ref }),
      });
      const data = await response.json();
      if (response.ok) {
        setBooking(data.booking);
        stopCamera();
      } else {
        setError(data.error || 'Booking not found.');
        setBooking(null);
      }
    } catch (err) {
      setError('Connection error.');
    } finally {
      setLoading(false);
    }
  };

  const validateAndProcessInput = (rawInput: string) => {
    setError(null);
    setScanFeedback(`Scanned: ${rawInput.length > 20 ? rawInput.substring(0, 17) + '...' : rawInput}`);

    // Clear feedback toast after 2 seconds
    setTimeout(() => setScanFeedback(null), 2000);

    const extracted = extractBookingRef(rawInput);

    if (!extracted) {
      setError("Not a booking QR. Please scan the customer booking QR.");
      return;
    }

    setBookingRef(extracted);
    lookupBooking(extracted);
  };

  const extractBookingRef = (input: string): string | null => {
    let cleanInput = input.trim();
    if (cleanInput.toLowerCase().includes('ref=')) {
      try {
        const normalized = cleanInput.replace('/#/', '/');
        const url = new URL(normalized);
        const param = url.searchParams.get('ref');
        if (param) return param.toUpperCase();
      } catch (e) {
        const parts = cleanInput.split(/[?&]ref=/i);
        if (parts.length > 1) return parts[1].split('&')[0].toUpperCase();
      }
    }
    const refRegex = /^[A-Z0-9]{6,12}$/i;
    if (refRegex.test(cleanInput)) return cleanInput.toUpperCase();
    return null;
  };

  const startCamera = async () => {
    setError(null);
    setCameraPermissionError(false);
    const html5QrCode = new Html5Qrcode("qr-reader");
    html5QrCodeRef.current = html5QrCode;
    try {
      await html5QrCode.start(
        { facingMode: "environment" },
        { 
          fps: 15, 
          qrbox: { width: 280, height: 280 },
          aspectRatio: 1.0
        },
        (decodedText) => {
          validateAndProcessInput(decodedText);
        },
        () => {}
      );
      setIsCameraActive(true);
    } catch (err) {
      console.error("Camera error:", err);
      setCameraPermissionError(true);
      setIsCameraActive(false);
    }
  };

  const stopCamera = async () => {
    if (html5QrCodeRef.current && html5QrCodeRef.current.isScanning) {
      await html5QrCodeRef.current.stop();
      setIsCameraActive(false);
    }
  };

  const handleAction = async (action: 'checkin' | 'pickup') => {
    if (!bookingRef || !booking) return;
    setLoading(true);
    setError(null);
    try {
      // Use the ARCHIVE endpoint for pickup to match business rules
      const endpoint = action === 'checkin' ? '/api/booking/checkin' : '/api/archive/pickup';
      const response = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ bookingRef, adminEmail: auth.currentUser?.email }),
      });
      if (response.ok) {
        triggerVibrate();
        setSuccessMessage(action === 'checkin' ? 'Checked in successfully ✅' : 'Picked up successfully ✅ Archived');

        // Update local status so UI reflects success immediately if not yet auto-navigated
        setBooking(prev => prev ? { ...prev, status: action === 'checkin' ? 'checked_in' : 'picked_up' } : null);

        // Auto-navigate after 2 seconds
        setTimeout(() => navigate('/'), 2000);
      } else {
        const data = await response.json();
        setError(data.error || 'Action failed.');
      }
    } catch (err) {
      setError('Connection error.');
    } finally {
      setLoading(false);
    }
  };

  const resetScanner = () => {
    setBooking(null);
    setBookingRef(null);
    setSuccessMessage(null);
    setManualInput('');
    startCamera();
  };

  return (
    <div className="fixed inset-0 bg-black flex flex-col overflow-hidden">
      {/* App Header */}
      <div className="flex-none bg-slate-900 px-6 py-6 flex items-center justify-between text-white border-b border-slate-800">
        <div className="flex items-center gap-3">
          <button onClick={() => navigate('/')} className="p-2 bg-slate-800 rounded-full hover:bg-slate-700 active:scale-90 transition-all">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
          </button>
          <div>
            <h1 className="text-lg font-black tracking-tight leading-none uppercase">Terminal</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Scanner</p>
          </div>
        </div>
        {!booking && !successMessage && (
           <button 
            onClick={resetScanner} 
            className="text-xs font-bold text-blue-400 hover:text-blue-300"
          >
             Reset
           </button>
        )}
      </div>

      <div className="flex-1 relative bg-slate-950 flex flex-col justify-center items-center">
        {/* Scan Feedback Toast */}
        {scanFeedback && (
          <div className="absolute top-8 left-1/2 -translate-x-1/2 z-50 bg-white/10 backdrop-blur-md border border-white/20 px-4 py-2 rounded-full text-[10px] font-black uppercase text-white tracking-widest animate-in fade-in slide-in-from-top-2">
            {scanFeedback}
          </div>
        )}

        {successMessage ? (
          <div className="w-full max-w-sm px-8 text-center animate-in zoom-in duration-300">
            <div className="w-24 h-24 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-8 border border-emerald-500/30">
              <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
            </div>
            <h2 className="text-3xl font-black text-white mb-4">Success!</h2>
            <p className="text-emerald-400 font-bold text-lg leading-tight mb-8">{successMessage}</p>

            <div className="space-y-3">
              <button 
                onClick={resetScanner}
                className="w-full py-4 bg-white/10 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] border border-white/10 hover:bg-white/20 transition-all"
              >
                Scan Next
              </button>
              <button 
                onClick={() => navigate('/')}
                className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-lg shadow-blue-500/20"
              >
                Back to List
              </button>
            </div>

            <p className="text-slate-500 text-[9px] mt-8 animate-pulse font-black uppercase tracking-widest">Auto-returning shortly...</p>
          </div>
        ) : booking ? (
          <div className="w-full max-w-lg px-6 animate-in slide-in-from-bottom duration-300">
            <div className="bg-white rounded-[2rem] shadow-2xl overflow-hidden border border-slate-200">
               <div className="p-8 space-y-8">
                  <div className="flex justify-between items-start">
                    <div>
                      <p className="text-[10px] font-black uppercase tracking-[0.2em] text-blue-600 mb-1">Booking Confirmed</p>
                      <h2 className="text-4xl font-black text-slate-900">#{booking.bookingRef}</h2>
                    </div>
                    <StatusBadge status={booking.status} />
                  </div>

                  <div className="space-y-4 bg-slate-50 p-6 rounded-3xl border border-slate-100">
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Customer</p>
                      <p className="font-black text-slate-900 text-lg">{booking.customer.name}</p>
                    </div>
                    <div className="border-t border-slate-200 pt-4">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Schedule</p>
                          <p className="font-bold text-slate-900 text-sm">{booking.dropOff.date}</p>
                          <p className="text-xs text-slate-500">{booking.dropOff.time}</p>
                        </div>
                        <div className="text-right">
                          <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Total Bags</p>
                          <p className="font-black text-slate-900 text-xl">{booking.bags.small + booking.bags.medium + booking.bags.large}</p>
                        </div>
                      </div>

                      <div className="grid grid-cols-3 gap-2 mt-4">
                         <div className="bg-white border border-slate-200 rounded-xl p-2 text-center shadow-sm">
                            <p className="text-lg font-black text-slate-900 leading-none">{booking.bags.small || 0}</p>
                            <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mt-1">Small</p>
                         </div>
                         <div className="bg-white border border-slate-200 rounded-xl p-2 text-center shadow-sm">
                            <p className="text-lg font-black text-slate-900 leading-none">{booking.bags.medium || 0}</p>
                            <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mt-1">Medium</p>
                         </div>
                         <div className="bg-white border border-slate-200 rounded-xl p-2 text-center shadow-sm">
                            <p className="text-lg font-black text-slate-900 leading-none">{booking.bags.large || 0}</p>
                            <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mt-1">Large</p>
                         </div>
                      </div>
                    </div>
                  </div>

                  <div className="space-y-4 pt-2">
                    {booking.status === 'paid' && (
                      <button
                        onClick={() => handleAction('checkin')}
                        disabled={loading}
                        className="w-full h-16 bg-blue-600 text-white rounded-2xl font-black text-xl hover:bg-blue-700 shadow-xl shadow-blue-500/20 transition-all active:scale-95 disabled:opacity-50"
                      >
                        {loading ? '...' : 'Confirm Check-In'}
                      </button>
                    )}

                    {booking.status === 'checked_in' && (
                      <button
                        onClick={() => handleAction('pickup')}
                        disabled={loading}
                        className="w-full h-16 bg-emerald-600 text-white rounded-2xl font-black text-xl hover:bg-emerald-700 shadow-xl shadow-emerald-500/20 transition-all active:scale-95 disabled:opacity-50"
                      >
                        {loading ? '...' : 'Mark Picked Up'}
                      </button>
                    )}

                    {(booking.status === 'picked_up' || booking.status === 'cancelled') && (
                      <div className="p-6 bg-slate-100 rounded-3xl text-center text-slate-500 font-black italic border border-slate-200">
                        Booking is {booking.status.replace('_', ' ')}
                      </div>
                    )}
                  </div>
               </div>
            </div>
            <button 
              onClick={resetScanner}
              className="w-full mt-6 text-white/50 font-bold text-sm uppercase tracking-[0.2em] hover:text-white transition-colors"
            >
              Scan Another
            </button>
          </div>
        ) : (
          <div className="w-full h-full flex flex-col">
            <div className="flex-1 relative flex items-center justify-center bg-black">
               <div id="qr-reader" className="w-full h-full"></div>
               {isCameraActive && (
                 <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                    <div className="w-[280px] h-[280px] border-2 border-white/30 rounded-[3rem] shadow-[0_0_0_1000px_rgba(0,0,0,0.6)] relative overflow-hidden">
                       <div className="absolute inset-0 border-[3px] border-blue-500/80 rounded-[3rem] animate-pulse"></div>
                       <div className="absolute top-0 left-0 right-0 h-1 bg-blue-500 shadow-[0_0_15px_rgba(59,130,246,1)] animate-[scan_3s_ease-in-out_infinite]"></div>
                    </div>
                 </div>
               )}
               {cameraPermissionError && (
                 <div className="absolute inset-0 bg-slate-900 flex flex-col items-center justify-center p-8 text-center z-20">
                    <h3 className="text-white text-xl font-black mb-2">Camera Blocked</h3>
                    <p className="text-slate-400 text-sm mb-8">Access is required to scan QR codes. Please update your browser permissions.</p>
                    <button onClick={startCamera} className="px-8 py-4 bg-white text-slate-900 rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl">Allow Camera</button>
                 </div>
               )}
            </div>

            <div className="flex-none bg-slate-900 p-8 pt-4 pb-12 rounded-t-[3rem] shadow-[0_-20px_50px_rgba(0,0,0,0.5)] border-t border-slate-800">
               <div className="w-12 h-1 bg-slate-700 rounded-full mx-auto mb-6"></div>
               <form onSubmit={(e) => { e.preventDefault(); validateAndProcessInput(manualInput); }} className="space-y-4">
                  <input 
                    type="text" 
                    value={manualInput}
                    onChange={(e) => setManualInput(e.target.value)}
                    placeholder="ENTER REFERENCE"
                    className="w-full h-16 bg-slate-800 border-2 border-slate-700 rounded-2xl text-white text-center text-xl font-black tracking-[0.2em] outline-none focus:border-blue-500 transition-all placeholder:text-slate-600 uppercase"
                  />
                  <button type="submit" className="w-full h-12 bg-slate-100 text-slate-900 rounded-xl text-sm font-black uppercase tracking-widest">
                    Search Booking
                  </button>
               </form>
               {error && (
                 <div className="mt-4 p-4 bg-red-500/10 text-red-500 rounded-2xl text-[10px] font-black uppercase tracking-widest text-center">
                    {error}
                 </div>
               )}
            </div>
          </div>
        )}
      </div>
      <style>{`
        @keyframes scan {
          0%, 100% { top: 10%; }
          50% { top: 90%; }
        }
      `}</style>
    </div>
  );
};

export default ScanPage;

import React, { useState, useEffect, useMemo } from 'react';
import { collection, getDocs, query, orderBy } from 'firebase/firestore';
import { useNavigate, Link } from 'react-router-dom';
import { auth, db } from '../firebase';
import { Booking } from '../types';
import { signOut } from 'firebase/auth';

type ReportMode = 'day' | 'month' | 'year';

interface ExtendedBooking extends Booking {
  _isArchive: boolean;
}

const ReportsPage: React.FC = () => {
  const navigate = useNavigate();
  const [activeBookings, setActiveBookings] = useState<ExtendedBooking[]>([]);
  const [archivedBookings, setArchivedBookings] = useState<ExtendedBooking[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [mode, setMode] = useState<ReportMode>('month');
  const [selectedDate, setSelectedDate] = useState(() => {
    const d = new Date();
    return d.toISOString().split('T')[0].substring(0, 7); // Default to current month YYYY-MM
  });

  const [archiveStatus, setArchiveStatus] = useState<{message: string, type: 'success' | 'error' | null}>({message: '', type: null});
  const [archiving, setArchiving] = useState(false);

  const logoUrl = "https://cdn.shopify.com/s/files/1/0753/8144/0861/files/cropped-Untitled-design-2025-09-11T094640.576_1.png?v=1765462614&width=160&format=webp";

  const fetchAllData = async () => {
    setLoading(true);
    setError(null);
    try {
      const qActive = query(collection(db, "bookings"), orderBy("createdAt", "desc"));
      const qArchive = query(collection(db, "bookings_archive"), orderBy("createdAt", "desc"));

      const [snapActive, snapArchive] = await Promise.all([
        getDocs(qActive),
        getDocs(qArchive)
      ]);

      const mapDocs = (snapshot: any, isArchive: boolean): ExtendedBooking[] => 
        snapshot.docs.map((d: any) => {
          const data: any = d.data();
          return {
            id: d.id,
            bookingRef: String(data.bookingRef ?? ""),
            stripeSessionId: String(data.stripeSessionId ?? ""),
            createdAt: data.createdAt ?? null,
            archivedAt: data.archivedAt ?? null,
            bookedOnRome: "",
            customer: {
              name: String(data.customer?.name ?? ""),
              email: String(data.customer?.email ?? ""),
              phone: String(data.customer?.phone ?? ""),
            },
            dropOff: {
              date: String(data.dropOff?.date ?? ""),
              time: String(data.dropOff?.time ?? ""),
              datetime: data.dropOff?.datetime ?? null,
            },
            pickUp: {
              date: String(data.pickUp?.date ?? ""),
              time: String(data.pickUp?.time ?? ""),
              datetime: data.pickUp?.datetime ?? null,
            },
            billableDays: Number(data.billableDays ?? 0),
            bags: {
              small: Number(data.bags?.small ?? 0),
              medium: Number(data.bags?.medium ?? 0),
              large: Number(data.bags?.large ?? 0),
            },
            totalPaid: Number(data.totalPaid ?? 0),
            currency: String(data.currency ?? "EUR"),
            status: data.status,
            notes: data.notes ?? data.dropOff?.notes ?? "",
            walletIssued: Boolean(data.walletIssued ?? false),
            _isArchive: isArchive
          };
        });

      setActiveBookings(mapDocs(snapActive, false));
      setArchivedBookings(mapDocs(snapArchive, true));
    } catch (err: any) {
      console.error("Error fetching report data:", err);
      setError(err instanceof Error ? err.message : String(err));
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAllData();
  }, []);

  const stats = useMemo(() => {
    const filterFn = (b: ExtendedBooking) => {
      const bDate = b.dropOff.date;
      if (mode === 'day') return bDate === selectedDate;
      if (mode === 'month') return bDate.startsWith(selectedDate);
      if (mode === 'year') return bDate.startsWith(selectedDate.substring(0, 4));
      return false;
    };

    const activeFiltered = activeBookings.filter(filterFn);
    const archivedFiltered = archivedBookings.filter(filterFn);
    const combined = [...activeFiltered, ...archivedFiltered];

    const totalBookings = combined.length;
    const revenue = combined.reduce((acc, b) => b.status !== 'cancelled' ? acc + b.totalPaid : acc, 0);

    const activeRevenue = activeFiltered.reduce((acc, b) => b.status !== 'cancelled' ? acc + b.totalPaid : acc, 0);
    const archivedRevenue = archivedFiltered.reduce((acc, b) => b.status !== 'cancelled' ? acc + b.totalPaid : acc, 0);

    const byStatus = {
      paid: combined.filter(b => b.status === 'paid').length,
      checked_in: combined.filter(b => b.status === 'checked_in').length,
      picked_up: combined.filter(b => b.status === 'picked_up').length,
      cancelled: combined.filter(b => b.status === 'cancelled').length,
    };

    return { 
      totalBookings, 
      revenue, 
      byStatus,
      breakdown: {
        active: { count: activeFiltered.length, rev: activeRevenue },
        archived: { count: archivedFiltered.length, rev: archivedRevenue }
      }
    };
  }, [activeBookings, archivedBookings, mode, selectedDate]);

  const handleArchiveAll = async () => {
    if (!window.confirm("Archive all checked-out bookings older than 7 days?")) return;
    setArchiving(true);
    setArchiveStatus({message: '', type: null});
    try {
      const response = await fetch('/api/archive/picked-up', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ days: 7 })
      });
      const data = await response.json();
      if (response.ok) {
        setArchiveStatus({message: `Success! Archived ${data.count} bookings.`, type: 'success'});
        fetchAllData();
      } else {
        setArchiveStatus({message: data.error || 'Archive failed.', type: 'error'});
      }
    } catch (err) {
      setArchiveStatus({message: 'Network error.', type: 'error'});
    } finally {
      setArchiving(false);
    }
  };

  const handleLogout = () => signOut(auth);

  return (
    <div className="min-h-screen bg-slate-50 pb-12 lg:pb-32 overflow-x-hidden">
      <header className="bg-white border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 lg:px-12 h-16 lg:h-24 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Link to="/"><img src={logoUrl} alt="Logo" className="h-8 lg:h-12 w-auto" /></Link>
            <h1 className="font-bold text-lg lg:text-2xl text-slate-900 tracking-tighter uppercase">Terminal</h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden md:flex items-center gap-4 lg:gap-12 mr-4 border-r pr-4 border-slate-200 lg:mr-10 lg:pr-10">
               <Link to="/" className="text-sm lg:text-lg font-bold text-slate-500 hover:text-blue-600 transition-colors">Bookings</Link>
               <Link to="/reports" className="text-sm lg:text-lg font-bold text-blue-600">Reports</Link>
            </div>
            <button onClick={handleLogout} className="text-sm lg:text-lg font-semibold text-slate-600 hover:text-red-600 transition-colors px-3 py-1.5 lg:px-8 lg:py-3.5 hover:bg-red-50 rounded-lg lg:rounded-2xl">Sign Out</button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 lg:px-12 mt-6 lg:mt-12">
        {error && (
          <div className="mb-6 p-4 lg:p-10 bg-red-50 border border-red-200 rounded-2xl lg:rounded-[3rem] text-red-700 animate-in fade-in slide-in-from-top-4 duration-300">
            <h3 className="font-bold text-sm lg:text-2xl uppercase tracking-wider mb-1 lg:mb-3">Reports Data Error</h3>
            <p className="text-xs lg:text-lg font-mono break-words">{error}</p>
          </div>
        )}

        <div className="mb-8 lg:mb-16">
            <h2 className="text-2xl lg:text-5xl font-black text-slate-900 tracking-tight">Performance Stats</h2>
            <p className="text-slate-500 lg:text-2xl mt-1 lg:mt-3">Analyze combined revenue from active and archived bookings</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 items-center gap-6 lg:gap-12 mb-8 lg:mb-16">
           <div className="flex bg-white p-1.5 lg:p-3 rounded-2xl lg:rounded-[2.5rem] border border-slate-200 shadow-sm w-fit">
              {(['day', 'month', 'year'] as const).map(m => (
                <button
                  key={m}
                  onClick={() => {
                    setMode(m);
                    if (m === 'year') setSelectedDate(new Date().getFullYear().toString());
                    else if (m === 'month') setSelectedDate(new Date().toISOString().substring(0, 7));
                    else setSelectedDate(new Date().toISOString().substring(0, 10));
                  }}
                  className={`px-6 py-2 lg:px-12 lg:py-5 text-sm lg:text-xl font-bold rounded-xl lg:rounded-[2rem] transition-all capitalize ${mode === m ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'text-slate-500 hover:text-slate-900'}`}
                >
                  {m}
                </button>
              ))}
           </div>
           <div className="flex items-center gap-3 lg:gap-8">
              <input 
                type={mode === 'day' ? 'date' : mode === 'month' ? 'month' : 'number'}
                className="bg-white border border-slate-200 rounded-xl lg:rounded-3xl px-4 py-2.5 lg:px-12 lg:py-6 font-black lg:text-3xl outline-none focus:ring-2 focus:ring-blue-500 shadow-sm transition-all"
                value={selectedDate}
                onChange={(e) => setSelectedDate(e.target.value)}
              />
              <span className="text-slate-400 text-[10px] lg:text-sm font-black uppercase tracking-[0.2em]">Period</span>
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 lg:gap-16 mb-12 lg:mb-24">
           <div className="bg-white p-8 lg:p-16 rounded-3xl lg:rounded-[4rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] lg:text-sm font-black text-slate-400 uppercase tracking-[0.2em] mb-2 lg:mb-6">Total Revenue</p>
              <p className="text-4xl lg:text-7xl font-black text-emerald-600">{stats.revenue.toLocaleString()} EUR</p>
           </div>
           <div className="bg-white p-8 lg:p-16 rounded-3xl lg:rounded-[4rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] lg:text-sm font-black text-slate-400 uppercase tracking-[0.2em] mb-2 lg:mb-6">Total Bookings</p>
              <p className="text-4xl lg:text-7xl font-black text-slate-900">{stats.totalBookings}</p>
           </div>
           <div className="bg-slate-900 p-8 lg:p-16 rounded-3xl lg:rounded-[4rem] text-white shadow-2xl shadow-slate-200">
              <p className="text-[10px] lg:text-sm font-black text-slate-400 uppercase tracking-[0.2em] mb-2 lg:mb-6">Avg. Per Booking</p>
              <p className="text-4xl lg:text-7xl font-black">{stats.totalBookings > 0 ? (stats.revenue / stats.totalBookings).toFixed(2) : '0'} <span className="text-lg lg:text-3xl opacity-50 uppercase font-medium">EUR</span></p>
           </div>
        </div>

        <div className="bg-orange-50 border border-orange-100 rounded-3xl lg:rounded-[5rem] p-8 lg:p-24">
           <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-6 lg:gap-16">
              <div className="max-w-3xl">
                 <h3 className="text-orange-900 font-black text-xl lg:text-4xl mb-1 lg:mb-6">Database Maintenance</h3>
                 <p className="text-orange-700 text-sm lg:text-2xl opacity-80 leading-relaxed">Archive legacy picked-up data to keep the system fast.</p>
              </div>
              <button onClick={handleArchiveAll} disabled={archiving} className="px-8 py-4 lg:px-20 lg:py-10 bg-orange-600 text-white rounded-2xl lg:rounded-[3rem] font-black lg:text-3xl hover:bg-orange-700 transition-all disabled:opacity-50 shadow-xl whitespace-nowrap">{archiving ? 'Processing...' : 'Run Catch-up Archive'}</button>
           </div>
           {archiveStatus.type && (
             <div className={`mt-6 lg:mt-16 p-4 lg:p-12 rounded-2xl lg:rounded-[3rem] text-sm lg:text-2xl font-black uppercase tracking-[0.2em] text-center ${archiveStatus.type === 'success' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                {archiveStatus.message}
             </div>
           )}
        </div>
      </main>
    </div>
  );
};

export default ReportsPage;

import React, { useState, useEffect, useRef } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { Html5Qrcode } from 'html5-qrcode';
import { auth } from '../firebase';
import StatusBadge from '../components/StatusBadge';

interface BookingSummary {
  id: string;
  bookingRef: string;
  customer: {
    name: string;
    email: string;
    phone: string;
  };
  bags: {
    small: number;
    medium: number;
    large: number;
  };
  dropOff: {
    date: string;
    time: string;
  };
  status: any;
}

const ScanPage: React.FC = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const initialRef = searchParams.get('ref') || searchParams.get('token');
  const [bookingRef, setBookingRef] = useState<string | null>(initialRef);
  const [manualInput, setManualInput] = useState('');
  const [booking, setBooking] = useState<BookingSummary | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [scanFeedback, setScanFeedback] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [cameraPermissionError, setCameraPermissionError] = useState(false);
  const html5QrCodeRef = useRef<Html5Qrcode | null>(null);

  // Auto-start camera on mount
  useEffect(() => {
    document.body.style.overflow = 'hidden';

    if (!bookingRef) {
      startCamera();
    } else {
      lookupBooking(bookingRef);
    }

    return () => {
      stopCamera();
      document.body.style.overflow = 'auto';
    };
  }, []);

  const triggerVibrate = () => {
    if ('vibrate' in navigator) {
      navigator.vibrate([200, 100, 200]);
    }
  };

